INSERT INTO sources VALUES ('SRC-02', 'DICCIONARIO raramuri.pdf');
INSERT INTO lexical_entries VALUES ('RD-000001', 'A', 'A', 'a', NULL, 'Vt', 'Vt', 'Buscar', 'Nijeni ama cahué. Voy a buscar el caballo. ¡Ábasi! ¡Vayan a buscarlo! [pret.: ari; fut.: ama] Ábia simíbari, fueron a buscarlo. Abo, lo buscaremos, uds. lo buscarán. Ásagá, si lo busca. Ásiga, buscándolo. Ay, lo buscaba.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000001-S01', 'RD-000001', 1, 'Buscar');
INSERT INTO examples VALUES ('RD-000001-E01', 'RD-000001', 1, 'Nijeni ama cahué. Voy a buscar el caballo. ¡Ábasi! ¡Vayan a buscarlo! [pret.: ari; fut.: ama] Ábia simíbari, fueron a buscarlo. Abo, lo buscaremos, uds. lo buscarán. Ásagá, si lo busca. Ásiga, buscándolo. Ay, lo buscaba.');
INSERT INTO variants VALUES ('RD-000001-V01', 'RD-000001', 1, 'pret.: ari; fut.: ama');
INSERT INTO lexical_entries VALUES ('RD-000002', 'Abé', 'Abé', 'abe', NULL, 'Adv', 'Adv', 'Hoy', '1. Abé huarú ucuri. Hoy llovió mucho. 2.Hace rato. Véase jipi, curipi.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000002-S01', 'RD-000002', 1, 'Hoy');
INSERT INTO examples VALUES ('RD-000002-E01', 'RD-000002', 1, '1. Abé huarú ucuri. Hoy llovió mucho. 2.Hace rato. Véase jipi, curipi.');
INSERT INTO lexical_entries VALUES ('RD-000003', 'Abi, abiyena', 'Abi, abiyena', 'abi, abiyena', NULL, 'Adv', 'Adv', 'Sí', '¿Acha mi ''yárati? Ayena, abi. ¿Se lo dieron? Sí.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000003-S01', 'RD-000003', 1, 'Sí');
INSERT INTO examples VALUES ('RD-000003-E01', 'RD-000003', 1, '¿Acha mi ''yárati? Ayena, abi. ¿Se lo dieron? Sí.');
INSERT INTO variants VALUES ('RD-000003-V01', 'RD-000003', 1, 'abiyena');
INSERT INTO lexical_entries VALUES ('RD-000004', 'Abijí', 'Abijí', 'abiji', NULL, 'Adv', 'Adv', 'Todavía, aún', '¡Abijí buhué!, ¡Espera todavía! Abijí que cho ucú, todavía no llueve. I''yábijí temprano todavía. Abijí tibíami, sobrante. Abijí ucú, todavía llueve.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000004-S01', 'RD-000004', 1, 'Todavía, aún');
INSERT INTO examples VALUES ('RD-000004-E01', 'RD-000004', 1, '¡Abijí buhué!, ¡Espera todavía! Abijí que cho ucú, todavía no llueve. I''yábijí temprano todavía. Abijí tibíami, sobrante. Abijí ucú, todavía llueve.');
INSERT INTO lexical_entries VALUES ('RD-000005', 'Aboni', 'Aboni', 'aboni', NULL, 'Pron', 'Pron', 'Ellos, ellas', 'Aboni pirérachi, habitación de ellos.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000005-S01', 'RD-000005', 1, 'Ellos, ellas');
INSERT INTO examples VALUES ('RD-000005-E01', 'RD-000005', 1, 'Aboni pirérachi, habitación de ellos.');
INSERT INTO lexical_entries VALUES ('RD-000006', 'Acá', '1Acá', 'aca', '1', 'S', 'S', 'Cara, nariz', 'Binoy acara, su cara. Binoy acárachi, en su cara. Véase cho''ó.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000006-S01', 'RD-000006', 1, 'Cara, nariz');
INSERT INTO examples VALUES ('RD-000006-E01', 'RD-000006', 1, 'Binoy acara, su cara. Binoy acárachi, en su cara. Véase cho''ó.');
INSERT INTO lexical_entries VALUES ('RD-000007', 'Acá', '2Acá', 'aca', '2', 'Vi', 'Vi', '1. Tener sal 2. Está dulce o sabroso', '¿Acha gará acá muní?, ¿Tienen suficiente sal los frijoles? Hue gará acá je''ná muní, están muy bien de sal estos frijoles.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000007-S01', 'RD-000007', 1, 'Tener sal');
INSERT INTO senses VALUES ('RD-000007-S02', 'RD-000007', 2, 'Está dulce o sabroso');
INSERT INTO examples VALUES ('RD-000007-E01', 'RD-000007', 1, '¿Acha gará acá muní?, ¿Tienen suficiente sal los frijoles? Hue gará acá je''ná muní, están muy bien de sal estos frijoles.');
INSERT INTO lexical_entries VALUES ('RD-000008', 'Acá', '3Acá', 'aca', '3', 'S', 'S', 'Huarache', 'Nijeni quetasi te acá, no tengo huaraches.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000008-S01', 'RD-000008', 1, 'Huarache');
