INSERT INTO lexical_entries VALUES ('RD-000012', 'Acá', '4Acá', 'aca', '4', 'Vi', 'Vi', 'Embotarse, quitarse (el filo)', 'Ripurá acari, se embotó el hacha.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
