INSERT INTO lexical_entries VALUES ('RD-000014', 'Acáanami', 'Acáanami', 'acaanami', NULL, 'Adj', 'Adj', 'Sano de pie o de brazo (se usa negativamente)', 'Echi rijoy que acáanami ju, mapujiti binoy ronórachi nacórami ju, Ese hombre es cojo porque tiene la pierna chueca. Que acáanami, cojo. Que acanáami biréana ronochí, cojo de una pierna.', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000014-S01', 'RD-000014', 1, 'Sano de pie o de brazo (se usa negativamente)');
INSERT INTO examples VALUES ('RD-000014-E01', 'RD-000014', 1, 'Echi rijoy que acáanami ju, mapujiti binoy ronórachi nacórami ju, Ese hombre es cojo porque tiene la pierna chueca. Que acáanami, cojo. Que acanáami biréana ronochí, cojo de una pierna.');
INSERT INTO lexical_entries VALUES ('RD-000015', 'Acabó', 'Acabó', 'acabo', NULL, 'S', 'S', 'Hoyo de la nariz, ventana de la nariz', '', 'SRC-02', '3', '3', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000015-S01', 'RD-000015', 1, 'Hoyo de la nariz, ventana de la nariz');
INSERT INTO lexical_entries VALUES ('RD-000016', 'Acáchura', 'Acáchura', 'acachura', NULL, 'S', 'S', '1. Abuela paterna 2. Nieta (de la abuela paterna)', 'Echi nijé onorá iyera nijé acáchura ju, la mamá de mi papá es mi abuela paterna. Nijé acáchura, mi abuela (la mamá de mi papá).', 'SRC-02', '3', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000016-S01', 'RD-000016', 1, 'Abuela paterna');
INSERT INTO senses VALUES ('RD-000016-S02', 'RD-000016', 2, 'Nieta (de la abuela paterna)');
INSERT INTO examples VALUES ('RD-000016-E01', 'RD-000016', 1, 'Echi nijé onorá iyera nijé acáchura ju, la mamá de mi papá es mi abuela paterna. Nijé acáchura, mi abuela (la mamá de mi papá).');
INSERT INTO lexical_entries VALUES ('RD-000017', 'Acahui', 'Acahui', 'acahui', NULL, 'Vt', 'Vt', 'Salar', '', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000017-S01', 'RD-000017', 1, 'Salar');
INSERT INTO lexical_entries VALUES ('RD-000018', 'Acajihua', 'Acajihua', 'acajihua', NULL, 'S', 'S', 'Correa', 'Acajihua ma su''rari, ya se soltó la correa del huarache.', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000018-S01', 'RD-000018', 1, 'Correa');
INSERT INTO examples VALUES ('RD-000018-E01', 'RD-000018', 1, 'Acajihua ma su''rari, ya se soltó la correa del huarache.');
INSERT INTO lexical_entries VALUES ('RD-000019', 'Acajihua', 'Acajihua', 'acajihua', NULL, 'Vr', 'Vr', 'Ponerse correas a los huaraches', 'Nijé acajíhuara, mis correas', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
