INSERT INTO lexical_entries VALUES ('RD-000020', 'Acami', 'Acami', 'acami', NULL, 'Adj sing', 'Adj', 'Vivo', 'Abijí acami ju cochí, todavía está vivo el perro.', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
