INSERT INTO examples VALUES ('RD-000020-E01', 'RD-000020', 1, 'Abijí acami ju cochí, todavía está vivo el perro.');
INSERT INTO lexical_entries VALUES ('RD-000021', 'Acaná', 'Acaná', 'acana', NULL, 'Adv', 'Adv', 'Boca abajo', 'Acaná huichiri, se cayó boca abajo. ¡Acaná achá bitori! ¡Voltea el cajete (boca abajo)!', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000021-S01', 'RD-000021', 1, 'Boca abajo');
INSERT INTO examples VALUES ('RD-000021-E01', 'RD-000021', 1, 'Acaná huichiri, se cayó boca abajo. ¡Acaná achá bitori! ¡Voltea el cajete (boca abajo)!');
INSERT INTO lexical_entries VALUES ('RD-000022', 'Acánami', 'Acánami', 'acanami', NULL, 'Pp', 'Pp', 'Aliviado (de pie, brazo, etc.), sano así', '', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000022-S01', 'RD-000022', 1, 'Aliviado (de pie, brazo, etc.), sano así');
