INSERT INTO lexical_entries VALUES ('RD-000025', 'Acha', 'Acha', 'acha', NULL, 'Adv', 'Adv', '¿Acaso…? (solo se usa en preguntas)', '¿Acha gará ju?, ¿Estás bien? ¿Quecha gará ju?, ¿No estás bien?', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000025-S01', 'RD-000025', 1, '¿Acaso…? (solo se usa en preguntas)');
INSERT INTO examples VALUES ('RD-000025-E01', 'RD-000025', 1, '¿Acha gará ju?, ¿Estás bien? ¿Quecha gará ju?, ¿No estás bien?');
INSERT INTO lexical_entries VALUES ('RD-000026', 'Achá', 'Achá', 'acha', NULL, 'Vt', 'Vt', 'Poner (una sola cosa o persona), colocar', 'Echo''ná achámani, voy a ponerlo allí. Nijeni naquiri echo''ná achayá, yo quería ponerlo allí. Echo''ná achárati, fue puesto allí. Sicochi achari rité, puso la piedra en el rincón. [pl.: muchuhua]', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000026-S01', 'RD-000026', 1, 'Poner (una sola cosa o persona), colocar');
INSERT INTO examples VALUES ('RD-000026-E01', 'RD-000026', 1, 'Echo''ná achámani, voy a ponerlo allí. Nijeni naquiri echo''ná achayá, yo quería ponerlo allí. Echo''ná achárati, fue puesto allí. Sicochi achari rité, puso la piedra en el rincón. [pl.: muchuhua]');
INSERT INTO variants VALUES ('RD-000026-V01', 'RD-000026', 1, 'pl.: muchuhua');
INSERT INTO lexical_entries VALUES ('RD-000027', 'Achagó', 'Achagó', 'achago', NULL, 'S', 'S', 'Una mata espinosa (semejante a la manzanilla; las chivas comen las ramitas)', 'Achagóachi, lugar donde hay esa mata.', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000027-S01', 'RD-000027', 1, 'Una mata espinosa (semejante a la manzanilla; las chivas comen las ramitas)');
INSERT INTO examples VALUES ('RD-000027-E01', 'RD-000027', 1, 'Achagóachi, lugar donde hay esa mata.');
INSERT INTO lexical_entries VALUES ('RD-000028', 'Achapa', 'Achapa', 'achapa', NULL, 'Vt', 'Vt', 'Golpear ropa o cobija sobre una roca o con un palo para quitar el agua.', '', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000028-S01', 'RD-000028', 1, 'Golpear ropa o cobija sobre una roca o con un palo para quitar el agua.');
INSERT INTO lexical_entries VALUES ('RD-000029', '''Aché', '''Aché', '''ache', NULL, 'Vi', 'Vi', 'Atiesarse (de frío), morirse (de frío)', 'Biré táa tohuí ''acheca mucuri, mapujiti quetasi teri quima, un niño chiquito se atiesó, y murió así, porque no tenía cobija.', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000029-S01', 'RD-000029', 1, 'Atiesarse (de frío), morirse (de frío)');
INSERT INTO examples VALUES ('RD-000029-E01', 'RD-000029', 1, 'Biré táa tohuí ''acheca mucuri, mapujiti quetasi teri quima, un niño chiquito se atiesó, y murió así, porque no tenía cobija.');
INSERT INTO lexical_entries VALUES ('RD-000030', 'Achí', 'Achí', 'achi', NULL, 'Vt', 'Vt', 'Reír, sonreír', 'Echi jaré rarámuri huabé achiri maparí nijé huichiri, los tarahumaras se rieron mucho cuando me caí.', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000030-S01', 'RD-000030', 1, 'Reír, sonreír');
INSERT INTO examples VALUES ('RD-000030-E01', 'RD-000030', 1, 'Echi jaré rarámuri huabé achiri maparí nijé huichiri, los tarahumaras se rieron mucho cuando me caí.');
INSERT INTO lexical_entries VALUES ('RD-000031', 'Achíami', 'Achíami', 'achiami', NULL, 'Adj', 'Adj', 'Risueño', '', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000031-S01', 'RD-000031', 1, 'Risueño');
INSERT INTO lexical_entries VALUES ('RD-000032', 'Achigó yiri ju', 'Achigó yiri ju', 'achigo yiri ju', NULL, '', 'Sin clasificar', 'Es igual', 'Véase néchigo', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
