INSERT INTO lexical_entries VALUES ('RD-000033', 'Achigórigá', 'Achigórigá', 'achigoriga', NULL, 'Adv', 'Adv', 'De la misma manera, así también', 'Echi rijoy nihuari biré namuti achigórigá mapurigá rihuari echo''ná huarúrachi, ese hombre hizo una cosa de la misma manera que vió en la ciudad.', 'SRC-02', '4', '4', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000033-S01', 'RD-000033', 1, 'De la misma manera, así también');
INSERT INTO examples VALUES ('RD-000033-E01', 'RD-000033', 1, 'Echi rijoy nihuari biré namuti achigórigá mapurigá rihuari echo''ná huarúrachi, ese hombre hizo una cosa de la misma manera que vió en la ciudad.');
