INSERT INTO lexical_entries VALUES ('RD-000047', 'Amí', 'Amí', 'ami', NULL, 'Vt', 'Vt', 'Buscar', 'Nijeni simea huenomí ámia, voy a buscar dinero Símabo huenomí ábia, vamos a buscar dinero. ¡Amí!, ¡Vaya a buscarlo! Ámia simiri, fue a buscarlo.', 'SRC-02', '5', '5', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
