INSERT INTO lexical_entries VALUES ('RD-000052', 'A’nabáa', 'A’nabáa', 'a''nabaa', NULL, 'Vi', 'Vi', 'Juntarse', 'Jena’í piréami pagótami a’nabáari echo’ná comurachi, la gente de aquí se juntó en la casa de la comunidad', 'SRC-02', '5', '5', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
