INSERT INTO lexical_entries VALUES ('RD-000053', 'Anacha', 'Anacha', 'anacha', NULL, 'Vi', 'Vi', 'Aguantar', 'Maparí rarajípari, échi rijoy quetasi anáchari, cuando corrieron con la bolsa, ese hombre no aguantó. Biquiyá norí chopi anáchari, solamente aguantó tres vueltas. Ne huabé ocó ramichí; nijeni quetasi omero huaminabi anacha, me duele mucho la muela; no puedo aguantarla más. [pret.: anáchari; fut.: anachama]', 'SRC-02', '5', '5', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000053-S01', 'RD-000053', 1, 'Aguantar');
INSERT INTO examples VALUES ('RD-000053-E01', 'RD-000053', 1, 'Maparí rarajípari, échi rijoy quetasi anáchari, cuando corrieron con la bolsa, ese hombre no aguantó. Biquiyá norí chopi anáchari, solamente aguantó tres vueltas. Ne huabé ocó ramichí; nijeni quetasi omero huaminabi anacha, me duele mucho la muela; no puedo aguantarla más. [pret.: anáchari; fut.: anachama]');
INSERT INTO variants VALUES ('RD-000053-V01', 'RD-000053', 1, 'pret.: anáchari; fut.: anachama');
