INSERT INTO lexical_entries VALUES ('RD-000057', 'Anahui', 'Anahui', 'anahui', NULL, 'Vt', 'Vt', 'Medir, pesar', 'Gará anáhuari echi sunú, mapurigá ibiri chópirigá chapimea, midieron bien el maíz, para que cada uno reciba la misma cantidad. [pret.: anpahuari; fut.: anáhuima]', 'SRC-02', '5', '6', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000057-S01', 'RD-000057', 1, 'Medir, pesar');
INSERT INTO examples VALUES ('RD-000057-E01', 'RD-000057', 1, 'Gará anáhuari echi sunú, mapurigá ibiri chópirigá chapimea, midieron bien el maíz, para que cada uno reciba la misma cantidad. [pret.: anpahuari; fut.: anáhuima]');
INSERT INTO variants VALUES ('RD-000057-V01', 'RD-000057', 1, 'pret.: anpahuari; fut.: anáhuima');
INSERT INTO lexical_entries VALUES ('RD-000058', 'A’nahuí', 'A’nahuí', 'a''nahui', NULL, 'Adv', 'Adv', '1. Al mismo tiempo 2. igual', 'A’nahuí ochérari, nacieron al mismo tiempo. Ne a’nahuí buyari, salieron al mismo tiempo. Ocuánica ne a''nahuí ju, los dos son iguales. A''nahuí ju, son iguales', 'SRC-02', '6', '6', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000058-S01', 'RD-000058', 1, 'Al mismo tiempo');
INSERT INTO senses VALUES ('RD-000058-S02', 'RD-000058', 2, 'igual');
INSERT INTO examples VALUES ('RD-000058-E01', 'RD-000058', 1, 'A’nahuí ochérari, nacieron al mismo tiempo. Ne a’nahuí buyari, salieron al mismo tiempo. Ocuánica ne a''nahuí ju, los dos son iguales. A''nahuí ju, son iguales');
INSERT INTO lexical_entries VALUES ('RD-000059', 'A''najata', 'A''najata', 'a''najata', NULL, 'Vt', 'Vt', 'Perseguir', 'Echi rijoy quimá chigósari, echijiti a''najátabo, ese hombre se robó una cobija; por eso lo perseguiremos. [pret.: a''najátari; fut.: a’najátama]', 'SRC-02', '6', '6', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
