INSERT INTO lexical_entries VALUES ('RD-000063', 'A''nayáhuari', 'A''nayáhuari', 'a''nayahuari', NULL, 'S pl', 'S', 'Los que vivieron hace mucho, los espíritus de los antepasados', 'Jaré rarámuri mayé mapu echi jaré qui''yá piréami pagótami arihuá abijí ''yena jena''í, echijiti maparí echi jaré rarámuri huabé majajáratami ju, rocogó niráa, aboni mayé mapu a''nayáhuari ''yena. Algunos tarahumaras creen que los espíritus de los que vivieron hace mucho todavía andan aquí, por eso, cuando ellos están muy asustados en la noche, creen que los espíritus de los antepasados andan por ahí.', 'SRC-02', '6', '6', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000063-S01', 'RD-000063', 1, 'Los que vivieron hace mucho, los espíritus de los antepasados');
INSERT INTO examples VALUES ('RD-000063-E01', 'RD-000063', 1, 'Jaré rarámuri mayé mapu echi jaré qui''yá piréami pagótami arihuá abijí ''yena jena''í, echijiti maparí echi jaré rarámuri huabé majajáratami ju, rocogó niráa, aboni mayé mapu a''nayáhuari ''yena. Algunos tarahumaras creen que los espíritus de los que vivieron hace mucho todavía andan aquí, por eso, cuando ellos están muy asustados en la noche, creen que los espíritus de los antepasados andan por ahí.');
INSERT INTO lexical_entries VALUES ('RD-000064', 'Ané', 'Ané', 'ane', NULL, 'Vt', 'Vt', 'Decir', 'Maparí echi rijoy ra''íchari tamí yuhua, binoy tamí aneri mapu binoy onorá ma mucuri, cuando ese hombre habló conmigo, me dijo que su papá ya había muerto.', 'SRC-02', '6', '6', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000064-S01', 'RD-000064', 1, 'Decir');
INSERT INTO examples VALUES ('RD-000064-E01', 'RD-000064', 1, 'Maparí echi rijoy ra''íchari tamí yuhua, binoy tamí aneri mapu binoy onorá ma mucuri, cuando ese hombre habló conmigo, me dijo que su papá ya había muerto.');
