INSERT INTO lexical_entries VALUES ('RD-000082', 'Apé', 'Apé', 'ape', NULL, 'Vt', 'Vt', 'Echar a la espalda', 'Nijé apema, yo voy a traerlo en la espalda. Echi rijoy apema cuco, ese hombre se va a echar un tercio de leña en la espalda.', 'SRC-02', '7', '7', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
