INSERT INTO lexical_entries VALUES ('RD-000090', 'Aré', 'Aré', 'are', NULL, 'Vt', 'Vt', 'Descornar', 'Echi toro tamí chi''iburi; ma huaminá arémani, ese toro me acorneó; ya voy a descornarlo.', 'SRC-02', '7', '7', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
