INSERT INTO lexical_entries VALUES ('RD-000094', 'Arigá', 'Arigá', 'ariga', NULL, '', 'Sin clasificar', 'A pesar de, de todos modos', 'Arigá ruráachi nochabo, a pesar del frío vamos a trabajar. Arigá ''huérari, urgente Ariga ''huérari ju, es menester', 'SRC-02', '7', '7', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000094-S01', 'RD-000094', 1, 'A pesar de, de todos modos');
INSERT INTO examples VALUES ('RD-000094-E01', 'RD-000094', 1, 'Arigá ruráachi nochabo, a pesar del frío vamos a trabajar. Arigá ''huérari, urgente Ariga ''huérari ju, es menester');
INSERT INTO lexical_entries VALUES ('RD-000095', 'Arihua', 'Arihua', 'arihua', NULL, 'Vi', 'Vi', 'Ser tarde, atardecer', 'Ma arihua, terico chonama, ya es tarde, pronto va a obscurecer.', 'SRC-02', '7', '7', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000095-S01', 'RD-000095', 1, 'Ser tarde, atardecer');
INSERT INTO examples VALUES ('RD-000095-E01', 'RD-000095', 1, 'Ma arihua, terico chonama, ya es tarde, pronto va a obscurecer.');
INSERT INTO lexical_entries VALUES ('RD-000096', 'Arihuá', 'Arihuá', 'arihua', NULL, 'S', 'S', 'Alma', '', 'SRC-02', '7', '7', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000096-S01', 'RD-000096', 1, 'Alma');
INSERT INTO lexical_entries VALUES ('RD-000097', 'Arihué', 'Arihué', 'arihue', NULL, 'Vt', 'Vt', 'Dejar', 'Rijoy huaminá arihueri binoy upira, el hombre dejó a su esposa. Echo''ná bitichí arihueri ripurá, dejó el hacha en la casa. ¡Arihué! ¡Quetasi namó orá!, ¡Déjalo! iNo le hagas nada! [pp.: arihuérami; fut.: arihuema]', 'SRC-02', '7', '7', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000097-S01', 'RD-000097', 1, 'Dejar');
INSERT INTO examples VALUES ('RD-000097-E01', 'RD-000097', 1, 'Rijoy huaminá arihueri binoy upira, el hombre dejó a su esposa. Echo''ná bitichí arihueri ripurá, dejó el hacha en la casa. ¡Arihué! ¡Quetasi namó orá!, ¡Déjalo! iNo le hagas nada! [pp.: arihuérami; fut.: arihuema]');
INSERT INTO variants VALUES ('RD-000097-V01', 'RD-000097', 1, 'pp.: arihuérami; fut.: arihuema');
INSERT INTO lexical_entries VALUES ('RD-000098', 'Arimuri', 'Arimuri', 'arimuri', NULL, 'S', 'S', 'Almud', '', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000098-S01', 'RD-000098', 1, 'Almud');
INSERT INTO lexical_entries VALUES ('RD-000099', 'A''rínaromí', 'A''rínaromí', 'a''rinaromi', NULL, 'Adv', 'Adv', 'Al poco rato', 'Maparimi cu simiri, que ayó, pe a''rínaromí échico nahuarí, a poco de haberse ido usted, llegó él.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000099-S01', 'RD-000099', 1, 'Al poco rato');
INSERT INTO examples VALUES ('RD-000099-E01', 'RD-000099', 1, 'Maparimi cu simiri, que ayó, pe a''rínaromí échico nahuarí, a poco de haberse ido usted, llegó él.');
INSERT INTO lexical_entries VALUES ('RD-000100', 'Ariósibá', 'Ariósibá', 'ariosiba', NULL, 'Interj', 'Interj', '¡Adiós!', '', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000100-S01', 'RD-000100', 1, '¡Adiós!');
