INSERT INTO senses VALUES ('RD-000103-S01', 'RD-000103', 1, 'Acudir');
INSERT INTO lexical_entries VALUES ('RD-000104', 'Asapa', 'Asapa', 'asapa', NULL, 'Vt', 'Vt', 'Sacudir', 'Cará asápari quimá, mapujiti hue napisóori. Sacudió bien la cobija, porque tenía mucho polvo.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000104-S01', 'RD-000104', 1, 'Sacudir');
INSERT INTO examples VALUES ('RD-000104-E01', 'RD-000104', 1, 'Cará asápari quimá, mapujiti hue napisóori. Sacudió bien la cobija, porque tenía mucho polvo.');
INSERT INTO lexical_entries VALUES ('RD-000105', 'Asayé', 'Asayé', 'asaye', NULL, 'S pl', 'S', 'Enemigos', '[sing.: sayé]', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
