INSERT INTO variants VALUES ('RD-000105-V01', 'RD-000105', 1, 'sing.: sayé');
INSERT INTO lexical_entries VALUES ('RD-000106', 'Asé', 'Asé', 'ase', NULL, 'Vt', 'Vt', 'Montar (un animal)', 'Cahué asigá cu simiri. Montando el caballo, se fué. Que cho binéami ju aserihua. Todavía no está entrenado a ser montado. Asigá montando', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000106-S01', 'RD-000106', 1, 'Montar (un animal)');
INSERT INTO examples VALUES ('RD-000106-E01', 'RD-000106', 1, 'Cahué asigá cu simiri. Montando el caballo, se fué. Que cho binéami ju aserihua. Todavía no está entrenado a ser montado. Asigá montando');
INSERT INTO lexical_entries VALUES ('RD-000107', 'Así', 'Así', 'asi', NULL, 'Adv', 'Adv', 'También', 'Binoy upira así simiri. Su esposa también se fue.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000107-S01', 'RD-000107', 1, 'También');
INSERT INTO examples VALUES ('RD-000107-E01', 'RD-000107', 1, 'Binoy upira así simiri. Su esposa también se fue.');
INSERT INTO lexical_entries VALUES ('RD-000108', 'Asibá', 'Asibá', 'asiba', NULL, 'Imper', 'Imper', 'Siéntate', 'Mami risiri inaria, echo''ná ritérari moba asibá. Ya te cansaste de andar, siéntate allí sobre la piedra.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000108-S01', 'RD-000108', 1, 'Siéntate');
INSERT INTO examples VALUES ('RD-000108-E01', 'RD-000108', 1, 'Mami risiri inaria, echo''ná ritérari moba asibá. Ya te cansaste de andar, siéntate allí sobre la piedra.');
INSERT INTO lexical_entries VALUES ('RD-000109', 'Asiba', 'Asiba', 'asiba', NULL, 'Vi sing', 'Vi', 'Sentarse', 'Pachá asíbaga, huarú co''huari. Sentándose adentro, comió mucho. Echo''ná escuélachi asíbami rihuárini. Le ví sentado allí, en la escuela.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000109-S01', 'RD-000109', 1, 'Sentarse');
INSERT INTO examples VALUES ('RD-000109-E01', 'RD-000109', 1, 'Pachá asíbaga, huarú co''huari. Sentándose adentro, comió mucho. Echo''ná escuélachi asíbami rihuárini. Le ví sentado allí, en la escuela.');
INSERT INTO lexical_entries VALUES ('RD-000110', 'Asiba', 'Asiba', 'asiba', NULL, '', 'Sin clasificar', 'Quedarse (cosa)', 'Echi huarú rité ripana jonsa cabótasa, huami ri’ré asíbari. Esa piedra rodó desde arriba y se quedó allí abajo. [pl.: muchiba] asináari vi quería sentarse', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000110-S01', 'RD-000110', 1, 'Quedarse (cosa)');
INSERT INTO examples VALUES ('RD-000110-E01', 'RD-000110', 1, 'Echi huarú rité ripana jonsa cabótasa, huami ri’ré asíbari. Esa piedra rodó desde arriba y se quedó allí abajo. [pl.: muchiba] asináari vi quería sentarse');
INSERT INTO variants VALUES ('RD-000110-V01', 'RD-000110', 1, 'pl.: muchiba');
INSERT INTO lexical_entries VALUES ('RD-000111', 'Asira', 'Asira', 'asira', NULL, 'Vi', 'Vi', 'Estar sentado (haciendo algo)', 'Oserí ''nénia asírari. Estaba sentado leyendo.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000111-S01', 'RD-000111', 1, 'Estar sentado (haciendo algo)');
INSERT INTO examples VALUES ('RD-000111-E01', 'RD-000111', 1, 'Oserí ''nénia asírari. Estaba sentado leyendo.');
