INSERT INTO senses VALUES ('RD-000118-S01', 'RD-000118', 1, 'Estornudar');
INSERT INTO lexical_entries VALUES ('RD-000119', 'Auché', 'Auché', 'auche', NULL, 'Adv', 'Adv', 'Otro', 'Auché baisá niráa, tres tantos. Auché biré, otro. Auché biréana, en otra parte. Auché biréara oméachi, el próximo domingo. Auché jaré, otros. Auché pe ocuá, otro poco. Auché siné, otra vez.', 'SRC-02', '8', '8', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000119-S01', 'RD-000119', 1, 'Otro');
INSERT INTO examples VALUES ('RD-000119-E01', 'RD-000119', 1, 'Auché baisá niráa, tres tantos. Auché biré, otro. Auché biréana, en otra parte. Auché biréara oméachi, el próximo domingo. Auché jaré, otros. Auché pe ocuá, otro poco. Auché siné, otra vez.');
INSERT INTO lexical_entries VALUES ('RD-000120', 'Auchecho', 'Auchecho', 'auchecho', NULL, '', 'Sin clasificar', '', 'Auchecho siné, otra vez. Auchecho siné aní, repetir. Auchecho siné cu ‘ya, reponer.', 'SRC-02', '8', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO examples VALUES ('RD-000120-E01', 'RD-000120', 1, 'Auchecho siné, otra vez. Auchecho siné aní, repetir. Auchecho siné cu ‘ya, reponer.');
INSERT INTO lexical_entries VALUES ('RD-000121', 'Ayá', 'Ayá', 'aya', NULL, '', 'Sin clasificar', 'Dando [Gerundio de ‘ya]', 'Jena’í iyénari biré óhuami carúmati ohuáami ayá. Aquí andaba un médico dándonos medicinas de todas clases.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000121-S01', 'RD-000121', 1, 'Dando [Gerundio de ‘ya]');
INSERT INTO examples VALUES ('RD-000121-E01', 'RD-000121', 1, 'Jena’í iyénari biré óhuami carúmati ohuáami ayá. Aquí andaba un médico dándonos medicinas de todas clases.');
INSERT INTO lexical_entries VALUES ('RD-000122', 'A’yapi', 'A’yapi', 'a''yapi', NULL, '', 'Sin clasificar', 'Uno tras otro', 'Maparí nachútari sunú, a’yapi sísari echi pagótuami. Cuando hicieron distribución del maíz, la gente llegaba una tras otra.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000122-S01', 'RD-000122', 1, 'Uno tras otro');
INSERT INTO examples VALUES ('RD-000122-E01', 'RD-000122', 1, 'Maparí nachútari sunú, a’yapi sísari echi pagótuami. Cuando hicieron distribución del maíz, la gente llegaba una tras otra.');
INSERT INTO lexical_entries VALUES ('RD-000123', 'Ayena', 'Ayena', 'ayena', NULL, 'Adv', 'Adv', 'Sí', '¿Acha atí mujé onorá? Ayena, echo''ná pachá atí. ¿Está tu papá? Sí, está allí adentro.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000123-S01', 'RD-000123', 1, 'Sí');
INSERT INTO examples VALUES ('RD-000123-E01', 'RD-000123', 1, '¿Acha atí mujé onorá? Ayena, echo''ná pachá atí. ¿Está tu papá? Sí, está allí adentro.');
INSERT INTO lexical_entries VALUES ('RD-000124', 'Ayena cho', 'Ayena cho', 'ayena cho', NULL, 'Adv', 'Adv', 'También, aún, sí', 'Ayena cho nayúnari echi jaré cúuchi. Aún los niños se enfermaron. Nijé onorá ayena cho nahuari. Mi papá también vino. Ayénasí, ayena así sí también.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000124-S01', 'RD-000124', 1, 'También, aún, sí');
INSERT INTO examples VALUES ('RD-000124-E01', 'RD-000124', 1, 'Ayena cho nayúnari echi jaré cúuchi. Aún los niños se enfermaron. Nijé onorá ayena cho nahuari. Mi papá también vino. Ayénasí, ayena así sí también.');
INSERT INTO lexical_entries VALUES ('RD-000125', 'Ba''arí', 'Ba''arí', 'ba''ari', NULL, 'Adv', 'Adv', 'Mañana.', 'Ba''arí bi''yá mañana temprano. Ba''arí piché hasta mañana', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000125-S01', 'RD-000125', 1, 'Mañana.');
INSERT INTO examples VALUES ('RD-000125-E01', 'RD-000125', 1, 'Ba''arí bi''yá mañana temprano. Ba''arí piché hasta mañana');
INSERT INTO lexical_entries VALUES ('RD-000126', 'Ba''arínara', 'Ba''arínara', 'ba''arinara', NULL, '', 'Sin clasificar', 'Al siguiente día (en el pasado) por la mañana', 'Maparí huarú quipari, ba''arínara huabé ruráari. Al día siguiente de la gran nevada hizo mucho frío.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000126-S01', 'RD-000126', 1, 'Al siguiente día (en el pasado) por la mañana');
INSERT INTO examples VALUES ('RD-000126-E01', 'RD-000126', 1, 'Maparí huarú quipari, ba''arínara huabé ruráari. Al día siguiente de la gran nevada hizo mucho frío.');
INSERT INTO lexical_entries VALUES ('RD-000127', 'Bacá', 'Bacá', 'baca', NULL, 'S', 'S', 'Carrizo', 'Huaminá tu bacochi hue nirú bacá. Allá abajo, en el río, hay mucho carrizo. Echi jaré rarámuri echi bacá nihuá cuseri. Los tarahumaras hacen flautas del carrizo.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000127-S01', 'RD-000127', 1, 'Carrizo');
INSERT INTO examples VALUES ('RD-000127-E01', 'RD-000127', 1, 'Huaminá tu bacochi hue nirú bacá. Allá abajo, en el río, hay mucho carrizo. Echi jaré rarámuri echi bacá nihuá cuseri. Los tarahumaras hacen flautas del carrizo.');
INSERT INTO lexical_entries VALUES ('RD-000128', 'Bacahuá', 'Bacahuá', 'bacahua', NULL, 'S', 'S', 'Hoja de la mazorca (seca)', '''Huisa, bacahuá napabusa, huaminánomí tamari nihuabo. En la pizca juntamos las hojas de las mazorcas; después haremos tamales.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000128-S01', 'RD-000128', 1, 'Hoja de la mazorca (seca)');
INSERT INTO examples VALUES ('RD-000128-E01', 'RD-000128', 1, '''Huisa, bacahuá napabusa, huaminánomí tamari nihuabo. En la pizca juntamos las hojas de las mazorcas; después haremos tamales.');
INSERT INTO lexical_entries VALUES ('RD-000129', 'Bacamú', 'Bacamú', 'bacamu', NULL, 'Vi', 'Vi', 'Infectarse (llaga), hincharse (con pus)', 'Chabé jonsa huabé cháanari, jipi ma bacamuri. Desde hace algún tiempo le salió un grano, ahora ya se hinchó con pus.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000129-S01', 'RD-000129', 1, 'Infectarse (llaga), hincharse (con pus)');
INSERT INTO examples VALUES ('RD-000129-E01', 'RD-000129', 1, 'Chabé jonsa huabé cháanari, jipi ma bacamuri. Desde hace algún tiempo le salió un grano, ahora ya se hinchó con pus.');
INSERT INTO lexical_entries VALUES ('RD-000130', 'Bacánuhui', 'Bacánuhui', 'bacanuhui', NULL, 'S', 'S', 'Tipo de mata que crece en las barrancas. (ellos usan las raíces bien machucadas con un poco de agua para curarse cuando están "fuera de sí".).', '', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000130-S01', 'RD-000130', 1, 'Tipo de mata que crece en las barrancas. (ellos usan las raíces bien machucadas con un poco de agua para curarse cuando están "fuera de sí".).');
INSERT INTO lexical_entries VALUES ('RD-000131', 'Bacarachi', 'Bacarachi', 'bacarachi', NULL, 'S', 'S', 'Tipo de víbora chica con rayas blancas', '', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000131-S01', 'RD-000131', 1, 'Tipo de víbora chica con rayas blancas');
INSERT INTO lexical_entries VALUES ('RD-000132', 'Bacarí', 'Bacarí', 'bacari', NULL, 'Vi', 'Vi', 'Tener enfermedad venérea', '', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000132-S01', 'RD-000132', 1, 'Tener enfermedad venérea');
INSERT INTO lexical_entries VALUES ('RD-000133', 'Bacó', 'Bacó', 'baco', NULL, 'Vi', 'Vi', 'Ponerse amarillo (las matas de maíz por haber llovido)', 'Chabé biréara michá huarú ucuri sinibí rahué, echijiti pachí ma bacori. Hace un mes llovió mucho todos los días, por eso las matas de maíz se pusieron amarillas.', 'SRC-02', '9', '9', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000133-S01', 'RD-000133', 1, 'Ponerse amarillo (las matas de maíz por haber llovido)');
INSERT INTO examples VALUES ('RD-000133-E01', 'RD-000133', 1, 'Chabé biréara michá huarú ucuri sinibí rahué, echijiti pachí ma bacori. Hace un mes llovió mucho todos los días, por eso las matas de maíz se pusieron amarillas.');
INSERT INTO lexical_entries VALUES ('RD-000134', 'Bacochi', 'Bacochi', 'bacochi', NULL, 'S', 'S', 'Río', 'Huamina ri''reti urí, huabé ri''ré bacochi ju. Allá en el fondo de la barranca, muy abajo, está el río.', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000134-S01', 'RD-000134', 1, 'Río');
INSERT INTO examples VALUES ('RD-000134-E01', 'RD-000134', 1, 'Huamina ri''reti urí, huabé ri''ré bacochi ju. Allá en el fondo de la barranca, muy abajo, está el río.');
INSERT INTO lexical_entries VALUES ('RD-000135', 'Bacúi', 'Bacúi', 'bacui', NULL, 'S', 'S', 'Otate', '', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000135-S01', 'RD-000135', 1, 'Otate');
INSERT INTO lexical_entries VALUES ('RD-000136', 'Bacúu', 'Bacúu', 'bacuu', NULL, 'S', 'S', 'Palo semejante al carrizo', '', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000136-S01', 'RD-000136', 1, 'Palo semejante al carrizo');
INSERT INTO lexical_entries VALUES ('RD-000137', 'Bacha', '1Bacha', 'bacha', '1', 'Adv', 'Adv', 'Primeramente, adelante, enfrente', 'Mapari mitebo biré oco, bachá niráa chutabo echi ripurá. Cuando tumbamos un pino, primeramente amolamos el hacha. Bachá huiríami, primogénito. Bachá niráa, de antemano. Bachá simí, avanza, precede', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000137-S01', 'RD-000137', 1, 'Primeramente, adelante, enfrente');
INSERT INTO examples VALUES ('RD-000137-E01', 'RD-000137', 1, 'Mapari mitebo biré oco, bachá niráa chutabo echi ripurá. Cuando tumbamos un pino, primeramente amolamos el hacha. Bachá huiríami, primogénito. Bachá niráa, de antemano. Bachá simí, avanza, precede');
INSERT INTO lexical_entries VALUES ('RD-000138', 'Bachá', '2Bachá', 'bacha', '2', 'Vipl', 'Vi', 'Meter (a la cárcel), poner (adentro)', '[pp.: bachárami] Bachánari. Quisieron ponerlo preso. Bachara asari, estaba preso, estaba encerrado', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000138-S01', 'RD-000138', 1, 'Meter (a la cárcel), poner (adentro)');
INSERT INTO examples VALUES ('RD-000138-E01', 'RD-000138', 1, '[pp.: bachárami] Bachánari. Quisieron ponerlo preso. Bachara asari, estaba preso, estaba encerrado');
INSERT INTO variants VALUES ('RD-000138-V01', 'RD-000138', 1, 'pp.: bachárami');
INSERT INTO lexical_entries VALUES ('RD-000139', 'Bacháami', 'Bacháami', 'bachaami', NULL, 'Adv', 'Adv', 'Ante, delante, por delante, enfrente de', 'Bacháami echi siríami yuhua huiribámani. Voy a comparecer delante del gobernador. Bacháami huiriami aparecer delante de, comparecer. Bacháami jaba comparecen.', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000139-S01', 'RD-000139', 1, 'Ante, delante, por delante, enfrente de');
INSERT INTO examples VALUES ('RD-000139-E01', 'RD-000139', 1, 'Bacháami echi siríami yuhua huiribámani. Voy a comparecer delante del gobernador. Bacháami huiriami aparecer delante de, comparecer. Bacháami jaba comparecen.');
INSERT INTO lexical_entries VALUES ('RD-000140', 'Bachagóachi', 'Bachagóachi', 'bachagoachi', NULL, 'S', 'S', 'Parte gruesa del hueso que fue roto', '', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000140-S01', 'RD-000140', 1, 'Parte gruesa del hueso que fue roto');
INSERT INTO lexical_entries VALUES ('RD-000141', 'Bachagochi', 'Bachagochi', 'bachagochi', NULL, 'S', 'S', 'Hueso del tobillo', '', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000141-S01', 'RD-000141', 1, 'Hueso del tobillo');
INSERT INTO lexical_entries VALUES ('RD-000142', 'Bachahuara', 'Bachahuara', 'bachahuara', NULL, 'Vi', 'Vi', 'Ir adelante.', 'Bachahuárari ichayá. Se apuró a sembrar primero. (lit.: adelante sembró) Nijeni hue jiyahua, echijiti bachahuáramani. Tengo mucha prisa; por eso voy adelante.', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000142-S01', 'RD-000142', 1, 'Ir adelante.');
INSERT INTO examples VALUES ('RD-000142-E01', 'RD-000142', 1, 'Bachahuárari ichayá. Se apuró a sembrar primero. (lit.: adelante sembró) Nijeni hue jiyahua, echijiti bachahuáramani. Tengo mucha prisa; por eso voy adelante.');
INSERT INTO lexical_entries VALUES ('RD-000143', 'Bachari', 'Bachari', 'bachari', NULL, 'Vt', 'Vt', 'Pret hacer preso', '', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000143-S01', 'RD-000143', 1, 'Pret hacer preso');
INSERT INTO lexical_entries VALUES ('RD-000144', 'Baché', 'Baché', 'bache', NULL, 'Vi', 'Vi', 'Apuntar bien jugando cuatro (tirando al hoyo)', '¡Gará baché! ¡Apúntelo bien!', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000144-S01', 'RD-000144', 1, 'Apuntar bien jugando cuatro (tirando al hoyo)');
INSERT INTO examples VALUES ('RD-000144-E01', 'RD-000144', 1, '¡Gará baché! ¡Apúntelo bien!');
INSERT INTO lexical_entries VALUES ('RD-000145', 'Bachéi', 'Bachéi', 'bachei', NULL, 'Vi', 'Vi', 'Tener hermano mayor', 'Nijeni quetasi bachéi, mapujiti nijé binoy bachá huiríami ju. No tengo hermano mayor, porque yo soy el primero.', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000145-S01', 'RD-000145', 1, 'Tener hermano mayor');
INSERT INTO examples VALUES ('RD-000145-E01', 'RD-000145', 1, 'Nijeni quetasi bachéi, mapujiti nijé binoy bachá huiríami ju. No tengo hermano mayor, porque yo soy el primero.');
INSERT INTO lexical_entries VALUES ('RD-000146', 'Bachi', '1Bachi', 'bachi', '1', 'S', 'S', 'Hermano mayor', 'Nijeni bachirúami ju, mapujítini bachá ochérami ju. Yo soy el primogénito, porque nací primero. Nijé bachirá mi hermano mayor.', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000146-S01', 'RD-000146', 1, 'Hermano mayor');
INSERT INTO examples VALUES ('RD-000146-E01', 'RD-000146', 1, 'Nijeni bachirúami ju, mapujítini bachá ochérami ju. Yo soy el primogénito, porque nací primero. Nijé bachirá mi hermano mayor.');
INSERT INTO lexical_entries VALUES ('RD-000147', 'Bachi', '2Bachi', 'bachi', '2', 'S', 'S', 'Calabaza.', 'Bachí sihuará, flor de calabaza', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000147-S01', 'RD-000147', 1, 'Calabaza.');
