INSERT INTO senses VALUES ('RD-000148-S01', 'RD-000148', 1, 'Rociar');
INSERT INTO lexical_entries VALUES ('RD-000149', 'Bachirúami', 'Bachirúami', 'bachiruami', NULL, 'Adj', 'Adj', 'Primogénito, hermano mayor', '', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000149-S01', 'RD-000149', 1, 'Primogénito, hermano mayor');
INSERT INTO lexical_entries VALUES ('RD-000150', 'Ba''hué', 'Ba''hué', 'ba''hue', NULL, 'Vi', 'Vi', 'Hay agua', 'Echo''ná huabé huaquichéami ju, quetasi ba''hué. Allí está muy seco, no hay agua. [pret.: ba''huéari; fut.: ba''huérama]', 'SRC-02', '10', '10', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000150-S01', 'RD-000150', 1, 'Hay agua');
INSERT INTO examples VALUES ('RD-000150-E01', 'RD-000150', 1, 'Echo''ná huabé huaquichéami ju, quetasi ba''hué. Allí está muy seco, no hay agua. [pret.: ba''huéari; fut.: ba''huérama]');
INSERT INTO variants VALUES ('RD-000150-V01', 'RD-000150', 1, 'pret.: ba''huéari; fut.: ba''huérama');
INSERT INTO lexical_entries VALUES ('RD-000151', 'Ba''huí', 'Ba''huí', 'ba''hui', NULL, 'S', 'S', 'Agua', 'Ba''huí túmani. Voy a traer agua. Ba''huí bají toma agua. Ba''huí huichirachi cascada. Ba''huí machina mana agua (p.ej.: de manantial). Ba''huí ro''hué riega. Ba''huí tuma trae agua. Huasí ba''huira jugo de fruta. Ba''huichí vi caer el sereno Jipi ma bará ju. Sinibí rahué bi''yá hue ba''huichí. Ahora es el tiempo de aguas. Todos los días, temprano, cae mucho sereno.', 'SRC-02', '10', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000151-S01', 'RD-000151', 1, 'Agua');
INSERT INTO examples VALUES ('RD-000151-E01', 'RD-000151', 1, 'Ba''huí túmani. Voy a traer agua. Ba''huí bají toma agua. Ba''huí huichirachi cascada. Ba''huí machina mana agua (p.ej.: de manantial). Ba''huí ro''hué riega. Ba''huí tuma trae agua. Huasí ba''huira jugo de fruta. Ba''huichí vi caer el sereno Jipi ma bará ju. Sinibí rahué bi''yá hue ba''huichí. Ahora es el tiempo de aguas. Todos los días, temprano, cae mucho sereno.');
INSERT INTO lexical_entries VALUES ('RD-000152', 'Bahuirá', 'Bahuirá', 'bahuira', NULL, 'Vt', 'Vt', 'Herrar', 'Ma bahuirabo echi huáasi, mapujiti nijé bucura ju. Ya vamos a herrar esa vaca,porque es mía.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000152-S01', 'RD-000152', 1, 'Herrar');
INSERT INTO examples VALUES ('RD-000152-E01', 'RD-000152', 1, 'Ma bahuirabo echi huáasi, mapujiti nijé bucura ju. Ya vamos a herrar esa vaca,porque es mía.');
INSERT INTO lexical_entries VALUES ('RD-000153', 'Ba''huira', 'Ba''huira', 'ba''huira', NULL, 'S', 'S', 'Jugo, caldo', 'Je''ná masana hue huaquichéami ju. Tasi te ba''huira. Esta manzana está muy seca. No tiene jugo. Masana ba''huira jugo de manzana.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000153-S01', 'RD-000153', 1, 'Jugo, caldo');
INSERT INTO examples VALUES ('RD-000153-E01', 'RD-000153', 1, 'Je''ná masana hue huaquichéami ju. Tasi te ba''huira. Esta manzana está muy seca. No tiene jugo. Masana ba''huira jugo de manzana.');
INSERT INTO lexical_entries VALUES ('RD-000154', 'Ba''huirá', 'Ba''huirá', 'ba''huira', NULL, 'Vi', 'Vi', 'Hacer caldo, echar agua a un líquido', 'Co''orí hue ba''huirari. Echó mucha agua al esquiate.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000154-S01', 'RD-000154', 1, 'Hacer caldo, echar agua a un líquido');
INSERT INTO examples VALUES ('RD-000154-E01', 'RD-000154', 1, 'Co''orí hue ba''huirari. Echó mucha agua al esquiate.');
INSERT INTO lexical_entries VALUES ('RD-000155', 'Baisá', 'Baisá', 'baisa', NULL, 'Adv', 'Adv', 'Tercero', '', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000155-S01', 'RD-000155', 1, 'Tercero');
INSERT INTO lexical_entries VALUES ('RD-000156', 'Baisá macoy', 'Baisá macoy', 'baisa macoy', NULL, 'Adj', 'Adj', 'Treinta', '', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000156-S01', 'RD-000156', 1, 'Treinta');
INSERT INTO lexical_entries VALUES ('RD-000157', 'Bajácami', 'Bajácami', 'bajacami', NULL, 'Pp', 'Pp', 'Hinchado', 'Huarú bajácami ju ramichí; ne huabé ocorá. Tengo muy hinchada la encía, porque la muela me duele mucho.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000157-S01', 'RD-000157', 1, 'Hinchado');
INSERT INTO examples VALUES ('RD-000157-E01', 'RD-000157', 1, 'Huarú bajácami ju ramichí; ne huabé ocorá. Tengo muy hinchada la encía, porque la muela me duele mucho.');
INSERT INTO lexical_entries VALUES ('RD-000158', 'Bají', 'Bají', 'baji', NULL, 'Vi', 'Vi', 'Tomar, beber (tesgüino, agua)', 'Echo''ná huarú maní suguí. Ba''arí bajima huareco. Allí hay mucho tesgüino. Tal vez van a tomar mañana. Bajimani ba''huí. Voy a tomar agua.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000158-S01', 'RD-000158', 1, 'Tomar, beber (tesgüino, agua)');
INSERT INTO examples VALUES ('RD-000158-E01', 'RD-000158', 1, 'Echo''ná huarú maní suguí. Ba''arí bajima huareco. Allí hay mucho tesgüino. Tal vez van a tomar mañana. Bajimani ba''huí. Voy a tomar agua.');
INSERT INTO lexical_entries VALUES ('RD-000159', 'Bajíami', 'Bajíami', 'bajiami', NULL, 'S', 'S', 'Curandero (que toma tesgüino)', '', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000159-S01', 'RD-000159', 1, 'Curandero (que toma tesgüino)');
INSERT INTO lexical_entries VALUES ('RD-000160', 'Bajíbachami', 'Bajíbachami', 'bajibachami', NULL, 'Pp', 'Pp', 'Hinchado por desnutrición', 'Echi tohui bajíbachami ju. Ne buchuhuí bajínari. Ese niño está hinchado por desnutrición. Se le hinchó todo el cuerpo.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000160-S01', 'RD-000160', 1, 'Hinchado por desnutrición');
INSERT INTO examples VALUES ('RD-000160-E01', 'RD-000160', 1, 'Echi tohui bajíbachami ju. Ne buchuhuí bajínari. Ese niño está hinchado por desnutrición. Se le hinchó todo el cuerpo.');
INSERT INTO lexical_entries VALUES ('RD-000161', 'Bajichahua', 'Bajichahua', 'bajichahua', NULL, 'Vi', 'Vi', 'Hacer norte (viento frío del norte)', '', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000161-S01', 'RD-000161', 1, 'Hacer norte (viento frío del norte)');
INSERT INTO lexical_entries VALUES ('RD-000162', 'Bajicháhuari', 'Bajicháhuari', 'bajichahuari', NULL, 'S', 'S', 'Norte (viento frío del norte)', 'Jipi ne huabé simírami ruráami icá. Hue bajicháhuari ju. Ahora está muy helado el aire. Es un norte.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000162-S01', 'RD-000162', 1, 'Norte (viento frío del norte)');
INSERT INTO examples VALUES ('RD-000162-E01', 'RD-000162', 1, 'Jipi ne huabé simírami ruráami icá. Hue bajicháhuari ju. Ahora está muy helado el aire. Es un norte.');
INSERT INTO lexical_entries VALUES ('RD-000163', 'Bajichi', 'Bajichi', 'bajichi', NULL, 'S', 'S', 'Pozo, ojo de agua, manantial.', 'Chabénara huaminá huaquicheri echo''ná bajichi; chopi jipi auchecho cu bajítari mapujiti ma gará ucú. Hace tiempo se secó allí donde salió agua; pero ya sale otra vez porque llueve bastante ahora.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000163-S01', 'RD-000163', 1, 'Pozo, ojo de agua, manantial.');
INSERT INTO examples VALUES ('RD-000163-E01', 'RD-000163', 1, 'Chabénara huaminá huaquicheri echo''ná bajichi; chopi jipi auchecho cu bajítari mapujiti ma gará ucú. Hace tiempo se secó allí donde salió agua; pero ya sale otra vez porque llueve bastante ahora.');
INSERT INTO lexical_entries VALUES ('RD-000164', 'Bajíhuachi', 'Bajíhuachi', 'bajihuachi', NULL, 'S', 'S', 'Tiempo de tomar tesgüino', 'Suguí bajíhuachi jaré rarámuri huabé nacohua. Algunos tarahumaras pelean mucho cuando es tiempo de tomar tesgüino.', 'SRC-02', '11', '11', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000164-S01', 'RD-000164', 1, 'Tiempo de tomar tesgüino');
INSERT INTO examples VALUES ('RD-000164-E01', 'RD-000164', 1, 'Suguí bajíhuachi jaré rarámuri huabé nacohua. Algunos tarahumaras pelean mucho cuando es tiempo de tomar tesgüino.');
INSERT INTO lexical_entries VALUES ('RD-000165', 'Bajíhuami', 'Bajíhuami', 'bajihuami', NULL, 'Adj', 'Adj', 'Potable (bebida)', '¿Acha bajíhuami ju? ¿Se puede tomar? (es potable). Ba''huí bajíhuami agua potable.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000165-S01', 'RD-000165', 1, 'Potable (bebida)');
INSERT INTO examples VALUES ('RD-000165-E01', 'RD-000165', 1, '¿Acha bajíhuami ju? ¿Se puede tomar? (es potable). Ba''huí bajíhuami agua potable.');
INSERT INTO lexical_entries VALUES ('RD-000166', 'Bajina', 'Bajina', 'bajina', NULL, 'Vi', 'Vi', 'Hincharse.', 'Hue ocorá ramichí, huarú bajínari nijé banarachi. Me duele mucho la muela, y se me hinchó mucho la mejilla. [pret.: bajínari; fut.: bajínama]', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000166-S01', 'RD-000166', 1, 'Hincharse.');
INSERT INTO examples VALUES ('RD-000166-E01', 'RD-000166', 1, 'Hue ocorá ramichí, huarú bajínari nijé banarachi. Me duele mucho la muela, y se me hinchó mucho la mejilla. [pret.: bajínari; fut.: bajínama]');
INSERT INTO variants VALUES ('RD-000166-V01', 'RD-000166', 1, 'pret.: bajínari; fut.: bajínama');
INSERT INTO lexical_entries VALUES ('RD-000167', 'Bajira', 'Bajira', 'bajira', NULL, 'Vt', 'Vt', 'Hacer tomar o beber.', 'Nijeni quetasi naquiri bajínara, chopi jaré rijoy tamí bajírari. Yo no quería tomar tesgüino, pero algunos hombres me hicieron tomarlo a la fuerza.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000167-S01', 'RD-000167', 1, 'Hacer tomar o beber.');
INSERT INTO examples VALUES ('RD-000167-E01', 'RD-000167', 1, 'Nijeni quetasi naquiri bajínara, chopi jaré rijoy tamí bajírari. Yo no quería tomar tesgüino, pero algunos hombres me hicieron tomarlo a la fuerza.');
INSERT INTO lexical_entries VALUES ('RD-000168', 'Bajita', 'Bajita', 'bajita', NULL, 'Vi', 'Vi', 'Salir agua', '[pret.: bajítari; fut.: bajítama]', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000168-S01', 'RD-000168', 1, 'Salir agua');
INSERT INTO examples VALUES ('RD-000168-E01', 'RD-000168', 1, '[pret.: bajítari; fut.: bajítama]');
