INSERT INTO lexical_entries VALUES ('RD-000169', 'Bajuhua', 'Bajuhua', 'bajuhua', NULL, 'Vi', 'Vi', 'Ir a la tesgüinada (a tomar)', 'Echi rijoy hue ra''iri suguí, echijiti ma simea bajuhua. A ese hombre le gusta mucho e l tesgüino; por eso se irá a l a tesgüinada.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000169-S01', 'RD-000169', 1, 'Ir a la tesgüinada (a tomar)');
INSERT INTO examples VALUES ('RD-000169-E01', 'RD-000169', 1, 'Echi rijoy hue ra''iri suguí, echijiti ma simea bajuhua. A ese hombre le gusta mucho e l tesgüino; por eso se irá a l a tesgüinada.');
INSERT INTO lexical_entries VALUES ('RD-000170', 'Bajuré', 'Bajuré', 'bajure', NULL, 'Vi', 'Vi', 'Invitar a la casa o al trabajo (a tomar tesgüino)', 'Jaré rarámuri huicabé bajuresa nochara. Algunos tarahumaras invitan a muchos a tomar tesgüino, pero los ponen a trabajar antes.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000170-S01', 'RD-000170', 1, 'Invitar a la casa o al trabajo (a tomar tesgüino)');
INSERT INTO examples VALUES ('RD-000170-E01', 'RD-000170', 1, 'Jaré rarámuri huicabé bajuresa nochara. Algunos tarahumaras invitan a muchos a tomar tesgüino, pero los ponen a trabajar antes.');
INSERT INTO lexical_entries VALUES ('RD-000171', 'Bajurí', 'Bajurí', 'bajuri', NULL, 'S', 'S', 'Nutria', 'Echi bajurí biré namuti ju, ri''ré ba''huichí iyénami. La nutria es un animal que puede nadar en el agua.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000171-S01', 'RD-000171', 1, 'Nutria');
INSERT INTO examples VALUES ('RD-000171-E01', 'RD-000171', 1, 'Echi bajurí biré namuti ju, ri''ré ba''huichí iyénami. La nutria es un animal que puede nadar en el agua.');
INSERT INTO lexical_entries VALUES ('RD-000172', 'Bamiba', 'Bamiba', 'bamiba', NULL, 'Vi', 'Vi', 'Hacer un año', 'Ma biré bamiba maparí mucuri nijé onorá. Ya hace un año que murió mi papá.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000172-S01', 'RD-000172', 1, 'Hacer un año');
INSERT INTO examples VALUES ('RD-000172-E01', 'RD-000172', 1, 'Ma biré bamiba maparí mucuri nijé onorá. Ya hace un año que murió mi papá.');
INSERT INTO lexical_entries VALUES ('RD-000173', 'Bamíbari', 'Bamíbari', 'bamibari', NULL, 'S', 'S', 'Año', 'Huicabé bamíbani. Chabé bamíbari. El año pasado. Chabé biquiyá bamíbari. El año pasado.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000173-S01', 'RD-000173', 1, 'Año');
INSERT INTO examples VALUES ('RD-000173-E01', 'RD-000173', 1, 'Huicabé bamíbani. Chabé bamíbari. El año pasado. Chabé biquiyá bamíbari. El año pasado.');
INSERT INTO lexical_entries VALUES ('RD-000174', 'Baná', 'Baná', 'bana', NULL, 'S', 'S', 'Mejilla', 'Tamí banarachi cho''nari. Me pegó en la mejilla. Banachí en la mejilla. Nijé banará. Mi mejilla.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000174-S01', 'RD-000174', 1, 'Mejilla');
INSERT INTO examples VALUES ('RD-000174-E01', 'RD-000174', 1, 'Tamí banarachi cho''nari. Me pegó en la mejilla. Banachí en la mejilla. Nijé banará. Mi mejilla.');
INSERT INTO lexical_entries VALUES ('RD-000175', 'Banagá', 'Banagá', 'banaga', NULL, 'S', 'S', 'Lama, moho', 'Ba''huí hue banagué. Hay mucha lama en el agua. Jipi hue nirú banagá echo''ná comichi. Ahora hay mucha lama allí, en el arroyo. Banagué vi hay lama.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000175-S01', 'RD-000175', 1, 'Lama, moho');
INSERT INTO examples VALUES ('RD-000175-E01', 'RD-000175', 1, 'Ba''huí hue banagué. Hay mucha lama en el agua. Jipi hue nirú banagá echo''ná comichi. Ahora hay mucha lama allí, en el arroyo. Banagué vi hay lama.');
INSERT INTO lexical_entries VALUES ('RD-000176', 'Banásani', 'Banásani', 'banasani', NULL, 'S', 'S', 'Víbora venenosa de menos de un metro, un poco negra, que no tiene cascabel, y vive en la barranca.', '', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000176-S01', 'RD-000176', 1, 'Víbora venenosa de menos de un metro, un poco negra, que no tiene cascabel, y vive en la barranca.');
INSERT INTO lexical_entries VALUES ('RD-000177', 'Bané', 'Bané', 'bane', NULL, 'Vi', 'Vi', 'Tener mejillas.', 'O''huari banéami ju. Tiene mejillas gordas. Banéami pp que tiene mejillas', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000177-S01', 'RD-000177', 1, 'Tener mejillas.');
INSERT INTO examples VALUES ('RD-000177-E01', 'RD-000177', 1, 'O''huari banéami ju. Tiene mejillas gordas. Banéami pp que tiene mejillas');
INSERT INTO lexical_entries VALUES ('RD-000178', 'Ba''nésara', 'Ba''nésara', 'ba''nesara', NULL, 'Vi', 'Vi', 'Gastarse la cobija', '', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000178-S01', 'RD-000178', 1, 'Gastarse la cobija');
INSERT INTO lexical_entries VALUES ('RD-000179', 'Ba''nésuri', 'Ba''nésuri', 'ba''nesuri', NULL, 'S', 'S', 'Una cobija gastada.', 'Nijé quimara ma ba''nésuri ju. Mi cobija ya está gastada.', 'SRC-02', '12', '12', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000179-S01', 'RD-000179', 1, 'Una cobija gastada.');
INSERT INTO examples VALUES ('RD-000179-E01', 'RD-000179', 1, 'Nijé quimara ma ba''nésuri ju. Mi cobija ya está gastada.');
INSERT INTO lexical_entries VALUES ('RD-000180', 'Banihuá', 'Banihuá', 'banihua', NULL, 'S', 'S', 'Cierta hierba que produce semillas manchadas de rojo y negro. Las muelen con agua y se ponen en una hueja cerca de la cruz cuando bailan matachines. Lo rocían sobre las chivas para curarlas, y para protegerlas contra las enfermedades.', '', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000180-S01', 'RD-000180', 1, 'Cierta hierba que produce semillas manchadas de rojo y negro. Las muelen con agua y se ponen en una hueja cerca de la cruz cuando bailan matachines. Lo rocían sobre las chivas para curarlas, y para protegerlas contra las enfermedades.');
INSERT INTO lexical_entries VALUES ('RD-000181', 'Banihuí', 'Banihuí', 'banihui', NULL, 'Vi', 'Vi', 'Crecer larga y enredada (mata)', 'I''huéari banihuiri bachí. Creció larga la mata de calabaza.', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000181-S01', 'RD-000181', 1, 'Crecer larga y enredada (mata)');
INSERT INTO examples VALUES ('RD-000181-E01', 'RD-000181', 1, 'I''huéari banihuiri bachí. Creció larga la mata de calabaza.');
INSERT INTO lexical_entries VALUES ('RD-000182', 'Banira', 'Banira', 'banira', NULL, 'Vt', 'Vt', 'Arrastrar, llevar (jalando con mecate).', 'Huíiga baníramani cahué. Voy a llevar el caballo jalandolo. Rojuá baníraga ipó achámani. Arrastrando ramas de encino, voy a echarlas en el barbecho para quemarlas ahí. [pret.: banírari; fut.: banírama, banagá]', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000182-S01', 'RD-000182', 1, 'Arrastrar, llevar (jalando con mecate).');
INSERT INTO examples VALUES ('RD-000182-E01', 'RD-000182', 1, 'Huíiga baníramani cahué. Voy a llevar el caballo jalandolo. Rojuá baníraga ipó achámani. Arrastrando ramas de encino, voy a echarlas en el barbecho para quemarlas ahí. [pret.: banírari; fut.: banírama, banagá]');
INSERT INTO variants VALUES ('RD-000182-V01', 'RD-000182', 1, 'pret.: banírari; fut.: banírama, banagá');
INSERT INTO lexical_entries VALUES ('RD-000183', 'Banisú', 'Banisú', 'banisu', NULL, 'Vt', 'Vt', 'Jalar (estirando)', 'Nijeni que omérari banisúhua echi cahué mapujiti hue aparú. No pude jalar ese caballo, porque está muy bravo.', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000183-S01', 'RD-000183', 1, 'Jalar (estirando)');
INSERT INTO examples VALUES ('RD-000183-E01', 'RD-000183', 1, 'Nijeni que omérari banisúhua echi cahué mapujiti hue aparú. No pude jalar ese caballo, porque está muy bravo.');
