INSERT INTO lexical_entries VALUES ('RD-000185', 'Baquí', 'Baquí', 'baqui', NULL, 'Vi', 'Vi', 'Entrar (solo)', 'Echi binériami ma baquiri pachá escuélachi, chopi echi jaré cúrohui que cho mo''huiri. El maestro ya entró a la escuela; pero los niños no han entrado todavía. [fut.: baquiméa; pl.: mo''hui]', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000185-S01', 'RD-000185', 1, 'Entrar (solo)');
INSERT INTO examples VALUES ('RD-000185-E01', 'RD-000185', 1, 'Echi binériami ma baquiri pachá escuélachi, chopi echi jaré cúrohui que cho mo''huiri. El maestro ya entró a la escuela; pero los niños no han entrado todavía. [fut.: baquiméa; pl.: mo''hui]');
INSERT INTO variants VALUES ('RD-000185-V01', 'RD-000185', 1, 'fut.: baquiméa; pl.: mo''hui');
INSERT INTO lexical_entries VALUES ('RD-000186', 'Baquirini', 'Baquirini', 'baquirini', NULL, 'S', 'S', 'Padrino, madrina', 'Echi rijoy nijé baquirínahuara ju. Échico tamí rihuarari. Ese hombre es mi padrino. El me puso mi nombre. Nijé baquirínahuara, mi padrino, mi madrina.', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000186-S01', 'RD-000186', 1, 'Padrino, madrina');
INSERT INTO examples VALUES ('RD-000186-E01', 'RD-000186', 1, 'Echi rijoy nijé baquirínahuara ju. Échico tamí rihuarari. Ese hombre es mi padrino. El me puso mi nombre. Nijé baquirínahuara, mi padrino, mi madrina.');
INSERT INTO lexical_entries VALUES ('RD-000187', 'Bará', 'Bará', 'bara', NULL, 'S', 'S', 'El tiempo de lluvias', 'Jipi ma bará ju; hue nirú pachí. Ya es tiempo de lluvias; hay muchos elotes. Que ''me ayó barásama. Pronto llegará el tiempo de lluvias.', 'SRC-02', '13', '13', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000187-S01', 'RD-000187', 1, 'El tiempo de lluvias');
INSERT INTO examples VALUES ('RD-000187-E01', 'RD-000187', 1, 'Jipi ma bará ju; hue nirú pachí. Ya es tiempo de lluvias; hay muchos elotes. Que ''me ayó barásama. Pronto llegará el tiempo de lluvias.');
