INSERT INTO lexical_entries VALUES ('RD-000193', 'Barí', 'Barí', 'bari', NULL, 'S', 'S', 'Quiote', 'Urí nirúami barí o''huari ju. E l quiote del maguey de l a barranca está muy grande. Me barirá, quiote de maguey. Barí sihuará, la flor de maguey.', 'SRC-02', '13', '14', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000193-S01', 'RD-000193', 1, 'Quiote');
INSERT INTO examples VALUES ('RD-000193-E01', 'RD-000193', 1, 'Urí nirúami barí o''huari ju. E l quiote del maguey de l a barranca está muy grande. Me barirá, quiote de maguey. Barí sihuará, la flor de maguey.');
