INSERT INTO lexical_entries VALUES ('RD-000199', 'Basiahui', 'Basiahui', 'basiahui', NULL, 'S', 'S', 'Triguillo (la semilla con que hacen fermentar el tesgüino)', 'Echi jaré rarámuri basiahui usuga napabú, echi suguí nasóhuaga nihuabia. Los tarahumaras juntan triguillo arrancandolo y lo mezclan para hacer el tesguino.', 'SRC-02', '14', '14', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
