INSERT INTO lexical_entries VALUES ('RD-000200', 'Basibú', 'Basibú', 'basibu', NULL, 'Vt', 'Vt', 'Apedrear', 'Riteti basibubo. Vamos a apedrearle. Basibúrami pp apedreado.', 'SRC-02', '14', '14', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
