INSERT INTO lexical_entries VALUES ('RD-000201', 'Basigó', '1Basigó', 'basigo', '1', 'Vi', 'Vi', 'Lavarse (la cara)', '¡Hue ochoréami jumi; gará basigó! ¡Estás muy mugroso; lávate bien la cara! Basigora vt le lava la cara.', 'SRC-02', '14', '14', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
