INSERT INTO lexical_entries VALUES ('RD-000202', 'Basigó', '2Basigó', 'basigo', '2', 'S', 'S', 'Hierba que sirve para calmar el dolor de muelas', 'Basigochi s lugar donde crece basigó.', 'SRC-02', '14', '14', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
