INSERT INTO lexical_entries VALUES ('RD-000216', 'Bayena', 'Bayena', 'bayena', NULL, 'S', 'S', 'Sanguijuela', 'Maparí cúrohui ba''huichí ''yena, echi bayena hue uchupa echi cúrohui ronórachi. Cuando los muchachos andan en el agua, las sanguijuelas les chupan . En los pies.', 'SRC-02', '15', '15', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
