INSERT INTO lexical_entries VALUES ('RD-000218', 'Ba''yó', 'Ba''yó', 'ba''yo', NULL, 'Vi', 'Vi', 'Parecer bonito, estar bonito', 'Hue ba''yó je''ná. Esto está muy bonito. Hue ba''yórarini sihuáchari. Me parecieron bonitas las flores.', 'SRC-02', '15', '15', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
