INSERT INTO lexical_entries VALUES ('RD-000223', 'Bicá', 'Bicá', 'bica', NULL, 'Vi', 'Vi', 'Pudrir', 'Ma biquiyari bachí. Ya se pudrió la calabaza. Chabé mucuri burito; ma huaminá biquiyari. Hace días que se murió el burro; ya se pudrió. [pret.: biquiyari; fut.: bicamea; pp.: bicáami]', 'SRC-02', '15', '15', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000223-S01', 'RD-000223', 1, 'Pudrir');
INSERT INTO examples VALUES ('RD-000223-E01', 'RD-000223', 1, 'Ma biquiyari bachí. Ya se pudrió la calabaza. Chabé mucuri burito; ma huaminá biquiyari. Hace días que se murió el burro; ya se pudrió. [pret.: biquiyari; fut.: bicamea; pp.: bicáami]');
