INSERT INTO lexical_entries VALUES ('RD-000230', 'Bichí', 'Bichí', 'bichi', NULL, 'Vi', 'Vi', 'Raspar, quitar la piel', 'Buhuichí i''mérini; hui''ré bichírini ronochí. Me caí en el camino; me raspé mucho (a lo largo) la pierna.', 'SRC-02', '15', '15', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
