INSERT INTO lexical_entries VALUES ('RD-000231', 'Bichihuá', 'Bichihuá', 'bichihua', NULL, 'S', 'S', 'Verdad', 'A bichihuá ju mapu ma nochama molinchi. Es verdad que ya van a trabajar en el molino.', 'SRC-02', '15', '15', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
