INSERT INTO senses VALUES ('RD-000241-S01', 'RD-000241', 1, 'Creyente');
INSERT INTO lexical_entries VALUES ('RD-000242', 'Bihuá', 'Bihuá', 'bihua', NULL, 'Vi', 'Vi', 'Estar duro', 'Ocuá tarari jonsa quetasi ucuri, echijiti hue bihuá huasarahua. Desde hace dos semanas no ha llovido, por eso está muy dura (la tierra) para barbechar. [pret.: bihuáari; fut.: bihuama]', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000242-S01', 'RD-000242', 1, 'Estar duro');
INSERT INTO examples VALUES ('RD-000242-E01', 'RD-000242', 1, 'Ocuá tarari jonsa quetasi ucuri, echijiti hue bihuá huasarahua. Desde hace dos semanas no ha llovido, por eso está muy dura (la tierra) para barbechar. [pret.: bihuáari; fut.: bihuama]');
INSERT INTO variants VALUES ('RD-000242-V01', 'RD-000242', 1, 'pret.: bihuáari; fut.: bihuama');
INSERT INTO lexical_entries VALUES ('RD-000243', 'Bi''huá', 'Bi''huá', 'bi''hua', NULL, 'Vt', 'Vt', 'Limpiar', 'Sipée huabé napisóami ju. ¡Gará cu bi''huá! El espejo tiene mucho polvo. ¡Limpialo bien!', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000243-S01', 'RD-000243', 1, 'Limpiar');
INSERT INTO examples VALUES ('RD-000243-E01', 'RD-000243', 1, 'Sipée huabé napisóami ju. ¡Gará cu bi''huá! El espejo tiene mucho polvo. ¡Limpialo bien!');
INSERT INTO lexical_entries VALUES ('RD-000244', 'Bihuachébana', 'Bihuachébana', 'bihuachebana', NULL, 'Vt', 'Vt', 'Endurecer', 'Ma bihuacheri bachí. Ya se endurecieron las calabazas. Jena''í ri''narátachi quetasi bihuárachi ju, gará bihuachébanabo, cusí chípérami jiti.Aquí, el patio no está duro. Vamos a endurecerlo con un palo ancho. Bihuaché vi endurecerse.', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000244-S01', 'RD-000244', 1, 'Endurecer');
INSERT INTO examples VALUES ('RD-000244-E01', 'RD-000244', 1, 'Ma bihuacheri bachí. Ya se endurecieron las calabazas. Jena''í ri''narátachi quetasi bihuárachi ju, gará bihuachébanabo, cusí chípérami jiti.Aquí, el patio no está duro. Vamos a endurecerlo con un palo ancho. Bihuaché vi endurecerse.');
INSERT INTO lexical_entries VALUES ('RD-000245', 'Bihuara', 'Bihuara', 'bihuara', NULL, 'Vt', 'Vt', 'Hacer duro', 'Bihuará vi endurecerse.', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000245-S01', 'RD-000245', 1, 'Hacer duro');
INSERT INTO examples VALUES ('RD-000245-E01', 'RD-000245', 1, 'Bihuará vi endurecerse.');
INSERT INTO lexical_entries VALUES ('RD-000246', 'Bihuárami', 'Bihuárami', 'bihuarami', NULL, 'Adv', 'Adv', 'Duro', '', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000246-S01', 'RD-000246', 1, 'Duro');
INSERT INTO lexical_entries VALUES ('RD-000247', 'Bi''huí', 'Bi''huí', 'bi''hui', NULL, 'Vi', 'Vi', 'Limpiarse, volverse blanco', 'Jabón jiti huichogá, gará bi''huimea. Lavándolo con jabón, se limpiará bien. ¿Acha gará bi''huiri huichohua? ¿se limpió bien al lavarlo?', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000247-S01', 'RD-000247', 1, 'Limpiarse, volverse blanco');
INSERT INTO examples VALUES ('RD-000247-E01', 'RD-000247', 1, 'Jabón jiti huichogá, gará bi''huimea. Lavándolo con jabón, se limpiará bien. ¿Acha gará bi''huiri huichohua? ¿se limpió bien al lavarlo?');
