INSERT INTO lexical_entries VALUES ('RD-000250', 'Bilini', 'Bilini', 'bilini', NULL, 'S', 'S', 'Fierro (de lumbre)', 'Echi rijoy gará machí na''ayá bilini, sorá yuhua. Ese hombre sabe hacer lumbre con un fierro y yesca.', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
