INSERT INTO lexical_entries VALUES ('RD-000252', 'Bimoré', 'Bimoré', 'bimore', NULL, 'Vi', 'Vi', 'Haber neblina, haber polvo, haber humo', 'Jipi rahue biyá hue bimoréari, nijeni mayé mapu quetasi ucumea. Hoy, temprano, había mucha neblina; creo que no va a llover [pret.: bimoréari; fut.: bimorema]. Bimoréami, que hay neblina', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000252-S01', 'RD-000252', 1, 'Haber neblina, haber polvo, haber humo');
INSERT INTO examples VALUES ('RD-000252-E01', 'RD-000252', 1, 'Jipi rahue biyá hue bimoréari, nijeni mayé mapu quetasi ucumea. Hoy, temprano, había mucha neblina; creo que no va a llover [pret.: bimoréari; fut.: bimorema]. Bimoréami, que hay neblina');
INSERT INTO variants VALUES ('RD-000252-V01', 'RD-000252', 1, 'pret.: bimoréari; fut.: bimorema');
