INSERT INTO lexical_entries VALUES ('RD-000254', 'Biné', 'Biné', 'bine', NULL, 'Vi', 'Vi', 'Aprender, estudiar', 'Chabé nijeni bineri oserí ''nénia. Hace tiempo aprendí a leer.', 'SRC-02', '16', '16', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
