INSERT INTO lexical_entries VALUES ('RD-000263', 'Biní', 'Biní', 'bini', NULL, 'S', 'S', 'Hermana menor (de mujer)', 'Queni biní, mi hermana menor (de mujer). Nijé binirá, mi hermana menor (de mujer).', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
