INSERT INTO lexical_entries VALUES ('RD-000264', 'Binorí', 'Binorí', 'binori', NULL, 'S', 'S', 'Anzuelo', 'Nijeni simiri echo''ná tu comichi, biré táa binorica. Fui por abajo, en el arroyo, llevando un anzuelo.', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
