INSERT INTO lexical_entries VALUES ('RD-000267', 'Biré', 'Biré', 'bire', NULL, 'Adj', 'Adj', 'Uno', 'Biré ciento, cien. Biré macori, un puñado de maíz', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
