INSERT INTO lexical_entries VALUES ('RD-000268', 'Biréana', 'Biréana', 'bireana', NULL, 'Adv', 'Adv', 'En una sola parte', 'Biréana ichárini, sembré en una sola parte. Ma quetasi te na''ibi; auché biréana simiri. Ya no está aquí; se fue a otra parte. Auché biréana, en otra parte, en alguna parte. Biréana burí, una yunta (de bueyes). Biréana busugachi, tuerto. Biréana huabé rocóhuachi, charco. Biréana ipó ichihuami, milpa. Biréana sobácohuachi, atascadero', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000268-S01', 'RD-000268', 1, 'En una sola parte');
INSERT INTO examples VALUES ('RD-000268-E01', 'RD-000268', 1, 'Biréana ichárini, sembré en una sola parte. Ma quetasi te na''ibi; auché biréana simiri. Ya no está aquí; se fue a otra parte. Auché biréana, en otra parte, en alguna parte. Biréana burí, una yunta (de bueyes). Biréana busugachi, tuerto. Biréana huabé rocóhuachi, charco. Biréana ipó ichihuami, milpa. Biréana sobácohuachi, atascadero');
INSERT INTO lexical_entries VALUES ('RD-000269', 'Biréanomí', 'Biréanomí', 'bireanomi', NULL, '', 'Sin clasificar', 'Una parte (desconocida), alguna parte', 'Biréanomí siméani, voy a alguna parte', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000269-S01', 'RD-000269', 1, 'Una parte (desconocida), alguna parte');
INSERT INTO examples VALUES ('RD-000269-E01', 'RD-000269', 1, 'Biréanomí siméani, voy a alguna parte');
INSERT INTO lexical_entries VALUES ('RD-000270', 'Birénapi', 'Birénapi', 'birenapi', NULL, 'Adv', 'Adv', 'En una sola parte', 'Birénapi nochabo, vamos a trabajar en una sola parte.', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000270-S01', 'RD-000270', 1, 'En una sola parte');
INSERT INTO examples VALUES ('RD-000270-E01', 'RD-000270', 1, 'Birénapi nochabo, vamos a trabajar en una sola parte.');
INSERT INTO lexical_entries VALUES ('RD-000271', 'Birepi', 'Birepi', 'birepi', NULL, 'Adv', 'Adv', 'Sólo uno', '¿Chú quipi riioy siri? Birepi nahuari, ¿Cuántos hombres vinieron? Llegó sólo uno.', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000271-S01', 'RD-000271', 1, 'Sólo uno');
INSERT INTO examples VALUES ('RD-000271-E01', 'RD-000271', 1, '¿Chú quipi riioy siri? Birepi nahuari, ¿Cuántos hombres vinieron? Llegó sólo uno.');
