INSERT INTO lexical_entries VALUES ('RD-000273', 'Bi''rí', 'Bi''rí', 'bi''ri', NULL, 'Vi', 'Vi', 'Torcerse', 'Ma bi''riri tabla, ya se torció la tabla.', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
