INSERT INTO senses VALUES ('RD-000275-S01', 'RD-000275', 1, 'Pedernal');
INSERT INTO lexical_entries VALUES ('RD-000276', 'Bi''rina', 'Bi''rina', 'bi''rina', NULL, 'Vt', 'Vt', 'Torcer, exprimir', 'Huíi bi''rinabo. Vamos a hacer (torcer) un mecate. Bo''osari bi''rinabo. Vamos a hacer hilo (torciendo la lana). [fut.: bi''rinama]. Bi''riná, torcer, dar vueltas (a alguna cosa)', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000276-S01', 'RD-000276', 1, 'Torcer, exprimir');
INSERT INTO examples VALUES ('RD-000276-E01', 'RD-000276', 1, 'Huíi bi''rinabo. Vamos a hacer (torcer) un mecate. Bo''osari bi''rinabo. Vamos a hacer hilo (torciendo la lana). [fut.: bi''rinama]. Bi''riná, torcer, dar vueltas (a alguna cosa)');
INSERT INTO variants VALUES ('RD-000276-V01', 'RD-000276', 1, 'fut.: bi''rinama');
INSERT INTO lexical_entries VALUES ('RD-000277', 'Bisiruta', 'Bisiruta', 'bisiruta', NULL, 'Vi', 'Vi', 'Rasparse', '', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
