INSERT INTO lexical_entries VALUES ('RD-000279', 'Bisú', 'Bisú', 'bisu', NULL, 'Vi', 'Vi', 'Despellejar', 'Maparí mi mi''risá echi huasi, hue yáati bisubo. Ya matando esa vaca, inmediatamente vamos a despellejarla.', 'SRC-02', '17', '17', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000279-S01', 'RD-000279', 1, 'Despellejar');
INSERT INTO examples VALUES ('RD-000279-E01', 'RD-000279', 1, 'Maparí mi mi''risá echi huasi, hue yáati bisubo. Ya matando esa vaca, inmediatamente vamos a despellejarla.');
INSERT INTO lexical_entries VALUES ('RD-000280', 'Bité', '1Bité', 'bite', '1', 'Vi', 'Vi', 'Sing habitar, morar, vivir', '¿Cumi bité?, ¿Dónde vives? Echo''ná basigóchi ni bité. Vivo allí, en Basigochi. [pret.: bitéeri; fut.: bitérama; pl.: piré]', 'SRC-02', '17', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000280-S01', 'RD-000280', 1, 'Sing habitar, morar, vivir');
INSERT INTO examples VALUES ('RD-000280-E01', 'RD-000280', 1, '¿Cumi bité?, ¿Dónde vives? Echo''ná basigóchi ni bité. Vivo allí, en Basigochi. [pret.: bitéeri; fut.: bitérama; pl.: piré]');
INSERT INTO variants VALUES ('RD-000280-V01', 'RD-000280', 1, 'pret.: bitéeri; fut.: bitérama; pl.: piré');
INSERT INTO lexical_entries VALUES ('RD-000281', 'Bité', '2Bité', 'bite', '2', 'Vi', 'Vi', 'Estar pesado', 'Ne huabé bité, quetásini omero o''huicha. Está muy pesado. No puedo levantarlo. [pret.: bitéari; fut.: bitítama]', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000281-S01', 'RD-000281', 1, 'Estar pesado');
INSERT INTO examples VALUES ('RD-000281-E01', 'RD-000281', 1, 'Ne huabé bité, quetásini omero o''huicha. Está muy pesado. No puedo levantarlo. [pret.: bitéari; fut.: bitítama]');
INSERT INTO variants VALUES ('RD-000281-V01', 'RD-000281', 1, 'pret.: bitéari; fut.: bitítama');
INSERT INTO lexical_entries VALUES ('RD-000282', 'Bitéami', 'Bitéami', 'biteami', NULL, 'Adj sin', 'Adj', 'Morador, que vive', 'Echi rijoy jena''í samichí bitéami ju. Ese hombre vive aquí en samachique. Huanihuí jena''í piréami napahuima. Pasado mañana se juntarán los que viven aquí. [pl.: piréami]', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000282-S01', 'RD-000282', 1, 'Morador, que vive');
INSERT INTO examples VALUES ('RD-000282-E01', 'RD-000282', 1, 'Echi rijoy jena''í samichí bitéami ju. Ese hombre vive aquí en samachique. Huanihuí jena''í piréami napahuima. Pasado mañana se juntarán los que viven aquí. [pl.: piréami]');
INSERT INTO variants VALUES ('RD-000282-V01', 'RD-000282', 1, 'pl.: piréami');
INSERT INTO lexical_entries VALUES ('RD-000283', 'Biteba', 'Biteba', 'biteba', NULL, 'Vi', 'Vi', 'Pasar la noche, pernoctar', 'Echo''ná cahuichí bitébari. Allí, en el campo, pasó la noche. [fut.: bitebama] Véase chi''reba', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000283-S01', 'RD-000283', 1, 'Pasar la noche, pernoctar');
INSERT INTO examples VALUES ('RD-000283-E01', 'RD-000283', 1, 'Echo''ná cahuichí bitébari. Allí, en el campo, pasó la noche. [fut.: bitebama] Véase chi''reba');
INSERT INTO variants VALUES ('RD-000283-V01', 'RD-000283', 1, 'fut.: bitebama');
INSERT INTO lexical_entries VALUES ('RD-000284', 'Bitechi', 'Bitechi', 'bitechi', NULL, 'S', 'S', 'Casa', 'Nijé bitérachi, mi casa. Queni bitechi, mi casa', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000284-S01', 'RD-000284', 1, 'Casa');
INSERT INTO examples VALUES ('RD-000284-E01', 'RD-000284', 1, 'Nijé bitérachi, mi casa. Queni bitechi, mi casa');
INSERT INTO lexical_entries VALUES ('RD-000285', 'Bití', 'Bití', 'biti', NULL, 'Vi pl', 'Vi', 'Estar acostados (varios)', 'Ri''ré huichí bitir, se acostaron en la tierra. Hui''rique rocogó bitíbari cochiboa, ya muy de noche se acostaron a dormir. [sing.: bu''huí; fut.: bitimea]. Bitibama, se acostarán. Bitisí ¡acuéstense!', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000285-S01', 'RD-000285', 1, 'Estar acostados (varios)');
INSERT INTO examples VALUES ('RD-000285-E01', 'RD-000285', 1, 'Ri''ré huichí bitir, se acostaron en la tierra. Hui''rique rocogó bitíbari cochiboa, ya muy de noche se acostaron a dormir. [sing.: bu''huí; fut.: bitimea]. Bitibama, se acostarán. Bitisí ¡acuéstense!');
INSERT INTO variants VALUES ('RD-000285-V01', 'RD-000285', 1, 'sing.: bu''huí; fut.: bitimea');
INSERT INTO lexical_entries VALUES ('RD-000286', 'Bitiba', 'Bitiba', 'bitiba', NULL, 'Vi', 'Vi', 'Echarse (animales), están acostándose', '', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
