INSERT INTO lexical_entries VALUES ('RD-000287', 'Bitichí', 'Bitichí', 'bitichi', NULL, 'S', 'S', 'Casa, habitación', 'Echo''ná bitichí iyénasí simiri, iba hacia la casa.', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
