INSERT INTO lexical_entries VALUES ('RD-000288', 'Bitira', 'Bitira', 'bitira', NULL, 'Vi', 'Vi', 'Andar (como borracho)', 'Capilata bitira, se revuelve (el caballo). Bitíra,echarse (de un lado al otro).', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
