INSERT INTO lexical_entries VALUES ('RD-000291', 'Bi''yá', 'Bi''yá', 'bi''ya', NULL, 'Adv', 'Adv', 'Temprano', 'Bi''yá rocogó, en la madrugada. Bi''yá chónachi, temprano (todavía está obscuro). Bi''yábijí, hoy temprano (todavía). Biyá chi''rásiachi, madrugada.', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
