INSERT INTO examples VALUES ('RD-000291-E01', 'RD-000291', 1, 'Bi''yá rocogó, en la madrugada. Bi''yá chónachi, temprano (todavía está obscuro). Bi''yábijí, hoy temprano (todavía). Biyá chi''rásiachi, madrugada.');
INSERT INTO lexical_entries VALUES ('RD-000292', 'Bocohuí', 'Bocohuí', 'bocohui', NULL, 'Vi', 'Vi', 'Ocultarse, ponerse el sol', 'Ma bocohuiri rayénari. Ya se puso el sol.', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
