INSERT INTO lexical_entries VALUES ('RD-000296', 'Bo''hué', 'Bo''hué', 'bo''hue', NULL, 'Vi', 'Vi', 'Tener lana, pelo', 'Hue bo''huéami ju echi bo''huá, ma siquiboa. Tiene mucha lana ese borrego; vamos a trasquilarlo. Pp.: bo''huéamil.', 'SRC-02', '18', '18', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
