INSERT INTO lexical_entries VALUES ('RD-000299', 'Boioní', 'Boioní', 'boioni', NULL, 'Vi', 'Vi', 'Pasar a pie al otro lado del agua, vadear', 'Maparí huabé bu''huíbari ba''huí, nijeni arigá boioniri. Cuando estaba muy crecida el agua, yo siempre pasaba al otro lado vadeando.', 'SRC-02', '18', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000299-S01', 'RD-000299', 1, 'Pasar a pie al otro lado del agua, vadear');
INSERT INTO examples VALUES ('RD-000299-E01', 'RD-000299', 1, 'Maparí huabé bu''huíbari ba''huí, nijeni arigá boioniri. Cuando estaba muy crecida el agua, yo siempre pasaba al otro lado vadeando.');
INSERT INTO lexical_entries VALUES ('RD-000300', 'Bo''ná', 'Bo''ná', 'bo''na', NULL, 'Vt', 'Vt', 'Arrancar, desherbar', 'O''huari ochérari mocuásari, ma cáraga bo''niboa. Creció mucho la hierba, ya vamos a arrancarla. [fut.: bo nomea]. Bo''nisí ¡arráncalos!', 'SRC-02', '19', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000300-S01', 'RD-000300', 1, 'Arrancar, desherbar');
INSERT INTO examples VALUES ('RD-000300-E01', 'RD-000300', 1, 'O''huari ochérari mocuásari, ma cáraga bo''niboa. Creció mucho la hierba, ya vamos a arrancarla. [fut.: bo nomea]. Bo''nisí ¡arráncalos!');
INSERT INTO variants VALUES ('RD-000300-V01', 'RD-000300', 1, 'fut.: bo nomea');
INSERT INTO lexical_entries VALUES ('RD-000301', 'Boní', 'Boní', 'boni', NULL, 'S', 'S', 'Hermano menor', 'Queni boní cu simiri, chopi nijé binirá abijí atí. Mi hermano menor se fue, pero mi hermana menor todavía está aquí. Nijé bonirá, mi hermano menor.', 'SRC-02', '19', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000301-S01', 'RD-000301', 1, 'Hermano menor');
INSERT INTO examples VALUES ('RD-000301-E01', 'RD-000301', 1, 'Queni boní cu simiri, chopi nijé binirá abijí atí. Mi hermano menor se fue, pero mi hermana menor todavía está aquí. Nijé bonirá, mi hermano menor.');
