INSERT INTO lexical_entries VALUES ('RD-000309', 'Bo''osari', 'Bo''osari', 'bo''osari', NULL, 'S', 'S', 'Lana', 'Bo''osari cabori, una bola de lana (para hacer cobijas). Bo''osari bi''rina, hace hilo de lana. Bo''osari rajana, carda la lana', 'SRC-02', '19', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
