INSERT INTO examples VALUES ('RD-000309-E01', 'RD-000309', 1, 'Bo''osari cabori, una bola de lana (para hacer cobijas). Bo''osari bi''rina, hace hilo de lana. Bo''osari rajana, carda la lana');
