INSERT INTO lexical_entries VALUES ('RD-000311', 'Boriba', 'Boriba', 'boriba', NULL, 'Vi', 'Vi', 'Correr el agua (en una corriente)', 'Maparí huarú bu''huíbari ba''huí, ne huabé boríbari. Cuando creció mucho el arroyo, corrió mucha agua.', 'SRC-02', '19', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000311-S01', 'RD-000311', 1, 'Correr el agua (en una corriente)');
INSERT INTO examples VALUES ('RD-000311-E01', 'RD-000311', 1, 'Maparí huarú bu''huíbari ba''huí, ne huabé boríbari. Cuando creció mucho el arroyo, corrió mucha agua.');
INSERT INTO lexical_entries VALUES ('RD-000312', 'Borogá', 'Borogá', 'boroga', NULL, 'Pp', 'Pp', 'Amarrado', 'Huíiti borogá cu tori. Amarrado con mecate, lo llevó. Borogá tobóa. Vamos a llevarlo amarrado. Véase buré', 'SRC-02', '19', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000312-S01', 'RD-000312', 1, 'Amarrado');
INSERT INTO examples VALUES ('RD-000312-E01', 'RD-000312', 1, 'Huíiti borogá cu tori. Amarrado con mecate, lo llevó. Borogá tobóa. Vamos a llevarlo amarrado. Véase buré');
INSERT INTO lexical_entries VALUES ('RD-000313', 'Bosá', 'Bosá', 'bosa', NULL, 'Vi sing', 'Vi', 'Llenarse, hartarse, (comiendo)', 'Huarúni bosari mapujiti huarú co''huari rimé. Me llené, porque comí muchas tortillas. [pl.: posá].', 'SRC-02', '19', '19', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000313-S01', 'RD-000313', 1, 'Llenarse, hartarse, (comiendo)');
INSERT INTO examples VALUES ('RD-000313-E01', 'RD-000313', 1, 'Huarúni bosari mapujiti huarú co''huari rimé. Me llené, porque comí muchas tortillas. [pl.: posá].');
INSERT INTO variants VALUES ('RD-000313-V01', 'RD-000313', 1, 'pl.: posá');
