INSERT INTO lexical_entries VALUES ('RD-000321', 'Bucura', 'Bucura', 'bucura', NULL, 'Adj', 'Adj', 'Poseedor (de un animal)', 'Nijé bucura cahué ju. Es mi caballo. ¿Chigá bucura ju? ¿Quién es el dueño? (del animal). Si''nu bucura, bestia ajena.', 'SRC-02', '19', '20', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000321-S01', 'RD-000321', 1, 'Poseedor (de un animal)');
INSERT INTO examples VALUES ('RD-000321-E01', 'RD-000321', 1, 'Nijé bucura cahué ju. Es mi caballo. ¿Chigá bucura ju? ¿Quién es el dueño? (del animal). Si''nu bucura, bestia ajena.');
INSERT INTO lexical_entries VALUES ('RD-000322', 'Bucurí', 'Bucurí', 'bucuri', NULL, 'Adv', 'Adv', 'Hace poco, nuevamente, hace rato', 'Bucurí cu nahuari. Hace poco volvió. Bucuripi, hace poquito, hace ratito. Bucurí, nihuá renueva. Bucurí nihuárami, recién hecho. Bucurí simíri, apenas salió.', 'SRC-02', '20', '20', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000322-S01', 'RD-000322', 1, 'Hace poco, nuevamente, hace rato');
INSERT INTO examples VALUES ('RD-000322-E01', 'RD-000322', 1, 'Bucurí cu nahuari. Hace poco volvió. Bucuripi, hace poquito, hace ratito. Bucurí, nihuá renueva. Bucurí nihuárami, recién hecho. Bucurí simíri, apenas salió.');
INSERT INTO lexical_entries VALUES ('RD-000323', 'Buchí', 'Buchí', 'buchi', NULL, 'Vi', 'Vi', 'Contener', 'Ocuá litro buchí. Contiene dos litros.', 'SRC-02', '20', '20', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
