INSERT INTO lexical_entries VALUES ('RD-000330', 'buhué', '1buhué', 'buhue', '1', 'Vt', 'Vt', 'Esperar', 'Echo''ná buhuichí nijeni mi buhuema. Allá, en el camino, te voy a esperar. Buhuesi! Imper pl éspérense!', 'SRC-02', '20', '20', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000330-S01', 'RD-000330', 1, 'Esperar');
INSERT INTO examples VALUES ('RD-000330-E01', 'RD-000330', 1, 'Echo''ná buhuichí nijeni mi buhuema. Allá, en el camino, te voy a esperar. Buhuesi! Imper pl éspérense!');
