INSERT INTO lexical_entries VALUES ('RD-000332', 'Bu''huí', 'Bu''huí', 'bu''hui', NULL, 'Vi', 'Vi', 'Acostarse (solo)', 'Hui''rique rocogó ju; m a bu''huíbari. Es muy noche; ya se acostó. Pachá carírari bu''huí. Está acostado adentro de la casa. [pl.: bití; fut.: bu’huimea, bu’huibamina]', 'SRC-02', '20', '20', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000332-S01', 'RD-000332', 1, 'Acostarse (solo)');
INSERT INTO examples VALUES ('RD-000332-E01', 'RD-000332', 1, 'Hui''rique rocogó ju; m a bu''huíbari. Es muy noche; ya se acostó. Pachá carírari bu''huí. Está acostado adentro de la casa. [pl.: bití; fut.: bu’huimea, bu’huibamina]');
INSERT INTO variants VALUES ('RD-000332-V01', 'RD-000332', 1, 'pl.: bití; fut.: bu’huimea, bu’huibamina');
INSERT INTO lexical_entries VALUES ('RD-000333', 'Buhuichí', 'Buhuichí', 'buhuichi', NULL, '', 'Sin clasificar', 'En el camino', 'Buhuichí bu''huíbari biré ocó huaquichéami. Se cayó un pino seco en el camino.', 'SRC-02', '20', '20', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000333-S01', 'RD-000333', 1, 'En el camino');
INSERT INTO examples VALUES ('RD-000333-E01', 'RD-000333', 1, 'Buhuichí bu''huíbari biré ocó huaquichéami. Se cayó un pino seco en el camino.');
