INSERT INTO lexical_entries VALUES ('RD-000361', 'Cáachi', 'Cáachi', 'caachi', NULL, 'Vi', 'Vi', 'Ser', 'Nijeni pe táa cáachi níiri. Yo era un poco chico. Ma ochérami cáachi mucumea. Ya que sea viejo, morirá. Siné cáachi. En otra ocasión, tal vez Táa cáachi. Siendo chico', 'SRC-02', '21', '21', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
