INSERT INTO lexical_entries VALUES ('RD-000362', 'Caba', 'Caba', 'caba', NULL, 'Vi', 'Vi', 'Estar bajo a la sombra', 'Nijeni echo’ná ri’ré pachá cábama. Voy a estar allí, a la sombra.', 'SRC-02', '21', '21', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
