INSERT INTO lexical_entries VALUES ('RD-000373', 'cachí', '1cachí', 'cachi', '1', 'Vi', 'Vi', 'Escupir', 'Ne huabé huaquicheri tambore. Gará níima cachípasa. El tambor se secó; sería bueno escupirlo. Cachipo. Vamos a escupir. Cachipa. Vi le escupe', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000373-S01', 'RD-000373', 1, 'Escupir');
INSERT INTO examples VALUES ('RD-000373-E01', 'RD-000373', 1, 'Ne huabé huaquicheri tambore. Gará níima cachípasa. El tambor se secó; sería bueno escupirlo. Cachipo. Vamos a escupir. Cachipa. Vi le escupe');
