INSERT INTO lexical_entries VALUES ('RD-000375', 'Cachígachí', 'Cachígachí', 'cachigachi', NULL, 'S', 'S', 'Cadera', 'Hue ocó nijé cachigárachi. Me duele mucho una cadera. Nijé cachigara. Mi cadera. Nijé cachigárachi. En mi cadera.', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000375-S01', 'RD-000375', 1, 'Cadera');
INSERT INTO examples VALUES ('RD-000375-E01', 'RD-000375', 1, 'Hue ocó nijé cachigárachi. Me duele mucho una cadera. Nijé cachigara. Mi cadera. Nijé cachigárachi. En mi cadera.');
INSERT INTO lexical_entries VALUES ('RD-000376', 'Cachú', 'Cachú', 'cachu', NULL, 'Vi', 'Vi', 'Arrugarse', 'Chabeni rarari je''ná coyacha; ma cáraga cachuri. Hace tiempo compré este sombrero; ya se arrugó completamente [pret.: cachuri]', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
