INSERT INTO lexical_entries VALUES ('RD-000378', 'Ca’huá', 'Ca’huá', 'ca''hua', NULL, 'Vt', 'Vt', 'Poner huevos', 'Jipi quetasi te ca’huara, echi torí quetasi ca’huá. Ahora no hay huevos, las gallinas no ponen. [fut.: ca''huaméa] Torí ca''huara. S huevos de galina.', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000378-S01', 'RD-000378', 1, 'Poner huevos');
INSERT INTO examples VALUES ('RD-000378-E01', 'RD-000378', 1, 'Jipi quetasi te ca’huara, echi torí quetasi ca’huá. Ahora no hay huevos, las gallinas no ponen. [fut.: ca''huaméa] Torí ca''huara. S huevos de galina.');
INSERT INTO variants VALUES ('RD-000378-V01', 'RD-000378', 1, 'fut.: ca''huaméa');
INSERT INTO lexical_entries VALUES ('RD-000379', 'Cahué', 'Cahué', 'cahue', NULL, 'S', 'S', 'Caballo', 'Cahué acará.herradura. Cahué buquéami. Dueño del caballo. Cahué cho''orá. El hocico del caballo. Cahué huasira. La cola del caballo Cahué muquira. Yegua. Cahué ropara. Vientre del caballo.', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000379-S01', 'RD-000379', 1, 'Caballo');
INSERT INTO examples VALUES ('RD-000379-E01', 'RD-000379', 1, 'Cahué acará.herradura. Cahué buquéami. Dueño del caballo. Cahué cho''orá. El hocico del caballo. Cahué huasira. La cola del caballo Cahué muquira. Yegua. Cahué ropara. Vientre del caballo.');
INSERT INTO lexical_entries VALUES ('RD-000380', 'Ca''hué', 'Ca''hué', 'ca''hue', NULL, 'Vi', 'Vi', 'Tener liendres', 'Hue ca''huéami ju mo''ochí. Tiene muchas liendres en la cabeza. [pret.: ca''huéari; fut.: ca''huérama]', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000380-S01', 'RD-000380', 1, 'Tener liendres');
INSERT INTO examples VALUES ('RD-000380-E01', 'RD-000380', 1, 'Hue ca''huéami ju mo''ochí. Tiene muchas liendres en la cabeza. [pret.: ca''huéari; fut.: ca''huérama]');
INSERT INTO variants VALUES ('RD-000380-V01', 'RD-000380', 1, 'pret.: ca''huéari; fut.: ca''huérama');
INSERT INTO lexical_entries VALUES ('RD-000381', 'Cahuera', 'Cahuera', 'cahuera', NULL, 'Vt', 'Vt', 'Menospreciar, despreciar', 'Echi rijoy quetasi tamí garé; chopi tamí cahuera. Ese hombre no me ama; solamente me desprecia.', 'SRC-02', '22', '22', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000381-S01', 'RD-000381', 1, 'Menospreciar, despreciar');
INSERT INTO examples VALUES ('RD-000381-E01', 'RD-000381', 1, 'Echi rijoy quetasi tamí garé; chopi tamí cahuera. Ese hombre no me ama; solamente me desprecia.');
INSERT INTO lexical_entries VALUES ('RD-000382', 'cahuí', '1cahuí', 'cahui', '1', 'S', 'S', 'Monte, terreno, tierra, campo, mundo', 'Iquecha mi cahuíi mapo’nami ichiméa? ¿no tienes tierra donde puedas sembrar? Cahuí ichihuáami. Tierra de cultivo. Cahuí pátami. Herencia de terrenos. Cahuíi. Vi tener tierra. Cahuichí. En el monte. Jena’í cahuírari. Este lugar. Nijé cahúíhuarachi. Mi tierra.', 'SRC-02', '22', '23', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000382-S01', 'RD-000382', 1, 'Monte, terreno, tierra, campo, mundo');
INSERT INTO examples VALUES ('RD-000382-E01', 'RD-000382', 1, 'Iquecha mi cahuíi mapo’nami ichiméa? ¿no tienes tierra donde puedas sembrar? Cahuí ichihuáami. Tierra de cultivo. Cahuí pátami. Herencia de terrenos. Cahuíi. Vi tener tierra. Cahuichí. En el monte. Jena’í cahuírari. Este lugar. Nijé cahúíhuarachi. Mi tierra.');
INSERT INTO lexical_entries VALUES ('RD-000383', 'cahuí', '2cahuí', 'cahui', '2', 'Vi', 'Vi', 'Aclarar (desaparecer las nubes)', 'Ma cu cahuiri norí. Ya se desaparecieron las nubes. Cahuí simí. Está aclarando.', 'SRC-02', '23', '23', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000383-S01', 'RD-000383', 1, 'Aclarar (desaparecer las nubes)');
