INSERT INTO lexical_entries VALUES ('RD-000555', 'Cu', '1Cu', 'cu', '1', 'Adv', 'Adv', 'Otra vez', 'Mani cu simea. Ya me voy (otra vez) Ma cu nahuari samichí cu. Ya vino a Samachique otra vez.', 'SRC-02', '29', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
