INSERT INTO examples VALUES ('RD-000555-E01', 'RD-000555', 1, 'Mani cu simea. Ya me voy (otra vez) Ma cu nahuari samichí cu. Ya vino a Samachique otra vez.');
INSERT INTO lexical_entries VALUES ('RD-000556', 'Cu', '2Cu', 'cu', '2', 'S', 'S', 'Leña, madera', 'Cu apera, llevar leña (en el lomo). Cu ca’hui, traer leña.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
