INSERT INTO lexical_entries VALUES ('RD-000561', 'Cuchíhua', 'Cuchíhua', 'cuchihua', NULL, 'Vi', 'Vi', 'Agusanarse', 'Chabé mucuri echi cochí, ma cáraca cuchíhuari. Hace tiempo murió ese perro; ya está completamente agusanado. Cuchíhuari, s Gusano de la carne', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
