INSERT INTO lexical_entries VALUES ('RD-000563', 'Cúchuhua', 'Cúchuhua', 'cuchuhua', NULL, 'Vt', 'Vt', 'Tener hijos', '¿Chu quipi mi cúchuhua? ¿Cuántos hijos tienes? Cúchuami, adj Que tiene hijos. Nijé cúchuhuara, mis hijos.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
