INSERT INTO lexical_entries VALUES ('RD-000564', 'Cuchuri', '1Cuchuri', 'cuchuri', '1', 'S', 'S', 'Grillo, oruga', 'Cuchuri hue cusú. Los grillos chirrían mucho.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
