INSERT INTO lexical_entries VALUES ('RD-000566', 'Cuhuana', '1Cuhuana', 'cuhuana', '1', 'Vt', 'Vt', '1. Tostar 2. Quemar (por el sol)', '¡Rimé cuhuana! ¡Tuesta la tortilla! Echi rayénari cara cuhuánari echi pachí. El sol quemó completamente las matas de maíz [fut.: cuhuanáma]. Cuhuanámari adj tostado.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000566-S01', 'RD-000566', 1, 'Tostar');
INSERT INTO senses VALUES ('RD-000566-S02', 'RD-000566', 2, 'Quemar (por el sol)');
INSERT INTO examples VALUES ('RD-000566-E01', 'RD-000566', 1, '¡Rimé cuhuana! ¡Tuesta la tortilla! Echi rayénari cara cuhuánari echi pachí. El sol quemó completamente las matas de maíz [fut.: cuhuanáma]. Cuhuanámari adj tostado.');
INSERT INTO variants VALUES ('RD-000566-V01', 'RD-000566', 1, 'fut.: cuhuanáma');
INSERT INTO lexical_entries VALUES ('RD-000567', 'Cuhuana', '2Cuhuana', 'cuhuana', '2', 'Adv', 'Adv', '1. Al otro lado, detrás 2. De nuevo', 'Huamí corí cuhuana bité. Él vive al otro lado (del cerro). Aboni auchecho cu cuhuana mi bayema. Ellos te invitarán de nuevo. Cochí cuhuana yori. El perro se enojó de nuevo.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000567-S01', 'RD-000567', 1, 'Al otro lado, detrás');
INSERT INTO senses VALUES ('RD-000567-S02', 'RD-000567', 2, 'De nuevo');
INSERT INTO examples VALUES ('RD-000567-E01', 'RD-000567', 1, 'Huamí corí cuhuana bité. Él vive al otro lado (del cerro). Aboni auchecho cu cuhuana mi bayema. Ellos te invitarán de nuevo. Cochí cuhuana yori. El perro se enojó de nuevo.');
INSERT INTO lexical_entries VALUES ('RD-000568', 'Cuhuara', 'Cuhuara', 'cuhuara', NULL, 'S', 'S', 'La punta (de pino, grano de maíz)', 'Ocó cuhuárachi atí biré cusá. En la punta del pino está una aguililla.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000568-S01', 'RD-000568', 1, 'La punta (de pino, grano de maíz)');
