INSERT INTO lexical_entries VALUES ('RD-000569', 'Cuhué', 'Cuhué', 'cuhue', NULL, 'S', 'S', 'El tiempo de calor (antes de las lluvias)', 'Jipi ma cu cuhué. Ya es el tiempo de calor. Cuhuesa. vi Llegar el tiempo de calor. Cuhuésachi. En el tiempo de calor.', 'SRC-02', '30', '30', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000569-S01', 'RD-000569', 1, 'El tiempo de calor (antes de las lluvias)');
INSERT INTO examples VALUES ('RD-000569-E01', 'RD-000569', 1, 'Jipi ma cu cuhué. Ya es el tiempo de calor. Cuhuesa. vi Llegar el tiempo de calor. Cuhuésachi. En el tiempo de calor.');
