INSERT INTO lexical_entries VALUES ('RD-000581', 'Cumá', 'Cumá', 'cuma', NULL, 'Vi', 'Vi', '1. Curar (con humo, p. ej.: gente, animales, siembra) 2. Limpiar con humo (después de enterrar a un muerto', 'Ichírari cumari. Curaron la siembra. Chibá cumabo. Vamos a curar las chivas, ahumeándolas.', 'SRC-02', '31', '31', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
