INSERT INTO lexical_entries VALUES ('RD-000582', 'Cumé', 'Cumé', 'cume', NULL, 'Vt', 'Vt', 'Estorbar, molestar', 'Tamí cumé. Me estorba. Echi rijoy huabé tamí cumeri. Ese hombre me estorbó mucho.', 'SRC-02', '31', '31', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
