INSERT INTO lexical_entries VALUES ('RD-000716', 'Chi’rá', '1Chi’rá', 'chi''ra', '1', 'Vi', 'Vi', 'Amanecer (el día)', 'Pe arí chi’riméaré. Tal vez va a amanecer en un rato. [fut.: chi’riméa].', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
