INSERT INTO lexical_entries VALUES ('RD-000718', 'Chi’rá', '3Chi’rá', 'chi''ra', '3', 'Vt', 'Vt', 'aplastar', 'Ripuchí chi’ránarini macúsahua jiti. Aplasté la pulga con mi dedo. Chi’rana. Vt aplastar (con el dedo).', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000718-S01', 'RD-000718', 1, 'aplastar');
INSERT INTO examples VALUES ('RD-000718-E01', 'RD-000718', 1, 'Ripuchí chi’ránarini macúsahua jiti. Aplasté la pulga con mi dedo. Chi’rana. Vt aplastar (con el dedo).');
INSERT INTO lexical_entries VALUES ('RD-000719', 'Chira, chirohua', 'Chira, chirohua', 'chira, chirohua', NULL, 'Vi', 'Vi', 'Cuchichear, murmurar', 'Chírahua anini. Se oye que cuchichean.', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
