INSERT INTO lexical_entries VALUES ('RD-000720', 'Chi’ré', '1Chi’ré', 'chi''re', '1', '', 'Sin clasificar', 'Importar', '¿Chu chiré? ¿Qué importa? Que chireco. No importa.', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
