INSERT INTO examples VALUES ('RD-000720-E01', 'RD-000720', 1, '¿Chu chiré? ¿Qué importa? Que chireco. No importa.');
INSERT INTO lexical_entries VALUES ('RD-000721', 'Chi’ré', '2Chi’ré', 'chi''re', '2', 'Vi', 'Vi', '1. pasar (un tiempo), pernoctar', 'Ma ocuá chi’reri. Ya hace dos días (pasaron dos noches). Ba’arí nahuó chi’rema. Mañana va a hacer cuatro días. Ocuá chi’rigá cu norínamani. Después de dos días regresaré.', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000721-S01', 'RD-000721', 1, '1. pasar (un tiempo), pernoctar');
INSERT INTO examples VALUES ('RD-000721-E01', 'RD-000721', 1, 'Ma ocuá chi’reri. Ya hace dos días (pasaron dos noches). Ba’arí nahuó chi’rema. Mañana va a hacer cuatro días. Ocuá chi’rigá cu norínamani. Después de dos días regresaré.');
INSERT INTO lexical_entries VALUES ('RD-000722', 'Chi’reba', 'Chi’reba', 'chi''reba', NULL, 'Vi', 'Vi', 'Pasarea la noche, posar', 'Gará chi’rébarini. Pasé bien la noche. Jena’í chi’ribámani. Aquí voy a pasar la noche.', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
