INSERT INTO lexical_entries VALUES ('RD-000724', 'Chirí', 'Chirí', 'chiri', NULL, 'S', 'S', 'Queja', 'Chirí anigá bitiri. Estaban acostados en el suelo gritando sus quejas. Chirí animéa. Dirá sus quejas en alta voz.', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
