INSERT INTO lexical_entries VALUES ('RD-000725', 'Chirigá', 'Chirigá', 'chiriga', NULL, 'Adv', 'Adv', 'De ninguna manera', 'Quetasi chirigá omérari. De ninguna manera pudieron.', 'SRC-02', '36', '36', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
