INSERT INTO lexical_entries VALUES ('RD-000731', 'Chi’rirú', 'Chi’rirú', 'chi''riru', NULL, 'Vt', 'Vt', 'Llevar (en la punta de un palito)', 'Mani mi’yair biré sayahui; cusiti chi’riruca micabé pámani. Ya maté una víbora de cascabel; la llevaré en la punta de un palito para tirarla lejos.', 'SRC-02', '36', '37', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
