INSERT INTO lexical_entries VALUES ('RD-000732', 'Chi’riruri', 'Chi’riruri', 'chi''riruri', NULL, 'S', 'S', 'El palo con que las mujeres tiran los aros cuando corren en las carreras.', 'Rohuera chi’riruri. Tiró el aro con un palito.', 'SRC-02', '37', '37', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
