INSERT INTO lexical_entries VALUES ('RD-000733', 'Chi’ró', 'Chi’ró', 'chi''ro', NULL, 'Vi', 'Vi', 'Salpicar, aletear, brincar', 'Ma pohuasa biré rochí, arí hue chi’roma. Cuando se agarra un pez con el anzuelo, entonces aletea mucho. Chi’ronó. Estar salpicando.', 'SRC-02', '37', '37', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
