INSERT INTO lexical_entries VALUES ('RD-000745', 'Chocoba', 'Chocoba', 'chocoba', NULL, '', 'Sin clasificar', '1. vi Hincarse, ponerse de rodillas 2. s Rodilla', '¡Chocoba huiribá! ¡Ponte de rodillas! Chocóbachi. En las rodillas. Chocóbaga huirí. Se arrodilla (sing.). Chocóbaga jahui. Se arrodillan (pl.). Chocóbachi. En la rodilla.', 'SRC-02', '37', '37', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000745-S01', 'RD-000745', 1, 'vi Hincarse, ponerse de rodillas');
INSERT INTO senses VALUES ('RD-000745-S02', 'RD-000745', 2, 's Rodilla');
INSERT INTO examples VALUES ('RD-000745-E01', 'RD-000745', 1, '¡Chocoba huiribá! ¡Ponte de rodillas! Chocóbachi. En las rodillas. Chocóbaga huirí. Se arrodilla (sing.). Chocóbaga jahui. Se arrodillan (pl.). Chocóbachi. En la rodilla.');
