INSERT INTO lexical_entries VALUES ('RD-000750', 'Cho’huá', 'Cho’huá', 'cho''hua', NULL, 'Vt', 'Vt', 'Apagar, extinguir (lumbre)', 'Nijeni sinibí cho’huá echi na’í maparini cu simea bitichí jonsa. Yo siempre apago la lumbre cuando salgo de la casa.', 'SRC-02', '37', '37', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
