INSERT INTO lexical_entries VALUES ('RD-000752', 'Cho’má', 'Cho’má', 'cho''ma', NULL, '', 'Sin clasificar', '1. s Moco 2. vi Resfriarse', 'Echo tohuí hue cho’meami ju. Ese niño tiene mucho moco. Cho’méami. Mocoso. Cho’mé. Vi Tener moco.', 'SRC-02', '37', '38', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
