INSERT INTO lexical_entries VALUES ('RD-000759', 'Cho’ná', 'Cho’ná', 'cho''na', NULL, 'Vt', 'Vt', 'Pegar (con la mano), abofetear, golpear (con alguna cosa)', 'Sicati capóriga cho’nari. Doblando el puño, le pegó. [fut.: cho’nimea]. Matochi cho’nogá. Tocando le hombro.', 'SRC-02', '38', '38', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
