INSERT INTO variants VALUES ('RD-000759-V01', 'RD-000759', 1, 'fut.: cho’nimea');
INSERT INTO lexical_entries VALUES ('RD-000760', 'Chona', 'Chona', 'chona', NULL, 'Vi', 'Vi', '1. Oscurecer 2. Ennegrecerse', 'Ma arihua, que ‘me ayó chonama. Ya es tarde, pronto oscurecerá. Echi táa tohuí ri’yeca chucú echo’ná napichi, cara chonama. Ese niñito está jugando en la chimenea; se va a tiznar (ennegrecer) completamente. [pret.: chónari; fut.: chonama]. Chónohua. Hacer negro. Chónami. Adv Sucio, oscuro.', 'SRC-02', '38', '38', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000760-S01', 'RD-000760', 1, 'Oscurecer');
INSERT INTO senses VALUES ('RD-000760-S02', 'RD-000760', 2, 'Ennegrecerse');
INSERT INTO examples VALUES ('RD-000760-E01', 'RD-000760', 1, 'Ma arihua, que ‘me ayó chonama. Ya es tarde, pronto oscurecerá. Echi táa tohuí ri’yeca chucú echo’ná napichi, cara chonama. Ese niñito está jugando en la chimenea; se va a tiznar (ennegrecer) completamente. [pret.: chónari; fut.: chonama]. Chónohua. Hacer negro. Chónami. Adv Sucio, oscuro.');
INSERT INTO variants VALUES ('RD-000760-V01', 'RD-000760', 1, 'pret.: chónari; fut.: chonama');
