INSERT INTO lexical_entries VALUES ('RD-000786', 'Chu', 'Chu', 'chu', NULL, 'Interr', 'Interr', '¿Qué?', '¿Chu anihuáami ju? ¿Qué quiere decir? ¿Chu iquí? ¿Qué pasa? ¿Chu mi iquiri? ¿Qué te parece? ¿Chu quipu? ¿Cuánto?, ¿qué cantidad? ¿Chu yena? ¿A qué hora? ¿Chu yena micabé ju? ¿Qué tan lejos está? ¿Chu yiri? ¿Qué clase?, ¿cuál?, ¿qué color?', 'SRC-02', '39', '39', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000786-S01', 'RD-000786', 1, '¿Qué?');
INSERT INTO examples VALUES ('RD-000786-E01', 'RD-000786', 1, '¿Chu anihuáami ju? ¿Qué quiere decir? ¿Chu iquí? ¿Qué pasa? ¿Chu mi iquiri? ¿Qué te parece? ¿Chu quipu? ¿Cuánto?, ¿qué cantidad? ¿Chu yena? ¿A qué hora? ¿Chu yena micabé ju? ¿Qué tan lejos está? ¿Chu yiri? ¿Qué clase?, ¿cuál?, ¿qué color?');
INSERT INTO lexical_entries VALUES ('RD-000787', 'Chúbirigá', 'Chúbirigá', 'chubiriga', NULL, 'Adv', 'Adv', 'De alguna manera', 'Chubirigá nihuabo. Vamos a hacerlo de alguna manera.', 'SRC-02', '39', '39', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
