INSERT INTO lexical_entries VALUES ('RD-000822', 'Churú', 'Churú', 'churu', NULL, 'S', 'S', 'Tamaño, tan grande', '¿Chu churubi? ¿Qué tan grande es? Je churú ju. Es de este tamaño. Pe táa ju, mapu churú echi táa racara. Es tan chiquito como esa pequeña semilla.', 'SRC-02', '40', '40', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
