INSERT INTO lexical_entries VALUES ('RD-000912', 'Huarú', 'Huarú', 'huaru', NULL, 'Adj sing', 'Adj', 'Grande, mucho, muy', 'Huarú bu’huíbari ba’huí. Creció mucho el arroyo. Huarú ucuri. Llovió mucho. Huarú sapéami ju. Está muy gordo. [pl.: ohuari]. Huarú ba’huechi. Mar. Huarú bahuechi suhué. Orilla del mar. Huarú chipérami. Como una tabla ancha. Huarú ritérari. Peñasco. Huarú sapéami. Panzón.', 'SRC-02', '43', '44', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000912-S01', 'RD-000912', 1, 'Grande, mucho, muy');
INSERT INTO examples VALUES ('RD-000912-E01', 'RD-000912', 1, 'Huarú bu’huíbari ba’huí. Creció mucho el arroyo. Huarú ucuri. Llovió mucho. Huarú sapéami ju. Está muy gordo. [pl.: ohuari]. Huarú ba’huechi. Mar. Huarú bahuechi suhué. Orilla del mar. Huarú chipérami. Como una tabla ancha. Huarú ritérari. Peñasco. Huarú sapéami. Panzón.');
