INSERT INTO lexical_entries VALUES ('RD-000951', '‘Huí', '‘Huí', '''hui', NULL, 'Vt', 'Vt', '1. Cosechar, pizcar el maíz 2. coger', '‘Huíi ‘yena. Andan pizcando maíz. Nijeni ‘huima pachí. Voy a pizcar maíz. [pret.: ‘huiri; fut.: ‘umea]. ‘Huíhuachi s La pizca, el tiempo de la pizca. ‘Huíhuami adj Que pertenece a la pizca. ‘Huisa vt Coger, agarrar, arrebatar ‘Usi imper pl ¡Cójanlo!', 'SRC-02', '45', '45', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000951-S01', 'RD-000951', 1, 'Cosechar, pizcar el maíz');
INSERT INTO senses VALUES ('RD-000951-S02', 'RD-000951', 2, 'coger');
INSERT INTO examples VALUES ('RD-000951-E01', 'RD-000951', 1, '‘Huíi ‘yena. Andan pizcando maíz. Nijeni ‘huima pachí. Voy a pizcar maíz. [pret.: ‘huiri; fut.: ‘umea]. ‘Huíhuachi s La pizca, el tiempo de la pizca. ‘Huíhuami adj Que pertenece a la pizca. ‘Huisa vt Coger, agarrar, arrebatar ‘Usi imper pl ¡Cójanlo!');
INSERT INTO variants VALUES ('RD-000951-V01', 'RD-000951', 1, 'pret.: ‘huiri; fut.: ‘umea');
