INSERT INTO lexical_entries VALUES ('RD-000955', 'Huica', 'Huica', 'huica', NULL, 'S', 'S', 'Palo picudo (para sembrar maíz)', 'Echi jaré rarámuri ichá huica jiti. Los tarahumaras siembran con el palo picudo.', 'SRC-02', '45', '45', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
