INSERT INTO lexical_entries VALUES ('RD-000977', 'Huichiba', 'Huichiba', 'huichiba', NULL, 'Vi', 'Vi', '1. Caer 2. Pegar (sol)', 'Jena’í huichiba aquibi echo comácari. por aquí cayó la bola. Bucurí huichíbachi rayénari nijeni asísari. Cuando comenzaba a pegar el sol en la mañana, me levanté. [pl.: rujuí].', 'SRC-02', '46', '46', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
