INSERT INTO lexical_entries VALUES ('RD-000983', 'Huichó', 'Huichó', 'huicho', NULL, 'Vt', 'Vt', 'Lavar (ropa)', 'Biré muquí echo’ná comichi huichó chucú. Una mujer está lavando allí, en el arroyo. Huichósohua táa nírari. Se encogió la ropa al lavarla.', 'SRC-02', '46', '46', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
