INSERT INTO lexical_entries VALUES ('RD-000995', 'Huijá', '1Huijá', 'huija', '1', 'Vt', 'Vt', 'Sacar (de la lumbre)', 'Nijeni huijiméa echi ri’rohui echo’ná napichi. Voy a sacar las papas de las cenizas. [fut.: huijaméa].', 'SRC-02', '47', '47', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000995-S01', 'RD-000995', 1, 'Sacar (de la lumbre)');
