INSERT INTO variants VALUES ('RD-000995-V01', 'RD-000995', 1, 'fut.: huijaméa');
INSERT INTO lexical_entries VALUES ('RD-000996', 'Huijá', '2Huijá', 'huija', '2', 'Vi', 'Vi', 'Estar colgado', 'Echo’ná pachá huijá chucú. Está colgado allí adentro. Huijagá chucú. Está colgado.', 'SRC-02', '47', '47', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
