INSERT INTO examples VALUES ('RD-000996-E01', 'RD-000996', 1, 'Echo’ná pachá huijá chucú. Está colgado allí adentro. Huijagá chucú. Está colgado.');
INSERT INTO lexical_entries VALUES ('RD-000997', 'Huijáhua', 'Huijáhua', 'huijahua', NULL, 'Vt', 'Vt', 'Colgar', 'Nijeni echo’ná huijpahuama echi juste. Voy a colgar el fuste allí adentro.', 'SRC-02', '47', '47', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
