INSERT INTO lexical_entries VALUES ('RD-000998', 'Hui’nijí', 'Hui’nijí', 'hui''niji', NULL, 'Vt', 'Vt', 'Acusar, condenar', 'Pagótami tamí hui’nijiri. La gente me acusaba. Comisario tamí hui’nijiri. El comisario de la policía me acusó. [fut.: hu’nijima]. Hui’nijíhuachi. Cuando lo acusan.', 'SRC-02', '47', '47', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-000998-S01', 'RD-000998', 1, 'Acusar, condenar');
INSERT INTO examples VALUES ('RD-000998-E01', 'RD-000998', 1, 'Pagótami tamí hui’nijiri. La gente me acusaba. Comisario tamí hui’nijiri. El comisario de la policía me acusó. [fut.: hu’nijima]. Hui’nijíhuachi. Cuando lo acusan.');
INSERT INTO variants VALUES ('RD-000998-V01', 'RD-000998', 1, 'fut.: hu’nijima');
