INSERT INTO lexical_entries VALUES ('RD-001002', 'Huipisó', 'Huipisó', 'huipiso', NULL, 'Vt', 'Vt', 'Azotar (con mano o cuarta), lo chicotea', 'Tamí huipisómia nahuari. Loegó par aazotarnos a nosotros. Muní huipisómani. Voy a desvainar el frijol (azotándolos). Huipisótami. Adj Azotado. Huipisónari. Querían azotarle. Huipisó capaneri. Toca la campana.', 'SRC-02', '47', '47', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001002-S01', 'RD-001002', 1, 'Azotar (con mano o cuarta), lo chicotea');
