INSERT INTO lexical_entries VALUES ('RD-001009', 'Hui´ré', 'Hui´ré', 'hui´re', NULL, 'Vi', 'Vi', 'Tener aretes', 'Echi moquí hue semati huir’e. Esa mujer tiene aretes muy bonitos.', 'SRC-02', '47', '47', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
