INSERT INTO lexical_entries VALUES ('RD-001010', 'Huirá', 'Huirá', 'huira', NULL, 'Vt', 'Vt', '1. Parar 2. Elegir, nombrar a una autoridad', 'Echo’ná sitochi huirari ripurá. Puso parada el hacha, en el rincón. Tamí huirábari capitani niráa. Me eligieron como capitán. [pl.: jahua; pret.: huirásari].', 'SRC-02', '47', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001010-S01', 'RD-001010', 1, 'Parar');
INSERT INTO senses VALUES ('RD-001010-S02', 'RD-001010', 2, 'Elegir, nombrar a una autoridad');
INSERT INTO examples VALUES ('RD-001010-E01', 'RD-001010', 1, 'Echo’ná sitochi huirari ripurá. Puso parada el hacha, en el rincón. Tamí huirábari capitani niráa. Me eligieron como capitán. [pl.: jahua; pret.: huirásari].');
