INSERT INTO lexical_entries VALUES ('RD-001013', 'Huirara', 'Huirara', 'huirara', NULL, 'Vi', 'Vi', 'Envejecerse (mujer)', 'Echi muquí ma hue huirárari. Esa mujer se ha envejecido mucho.', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
