INSERT INTO lexical_entries VALUES ('RD-001015', 'Hui’ré', 'Hui’ré', 'hui''re', NULL, 'Adj', 'Adj', 'Ancho', 'Hui’ré inaro ba’huí. Está ancho el río. Hui’ré ichiméani. Voy a sembrar ancho (mucho).', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001015-S01', 'RD-001015', 1, 'Ancho');
INSERT INTO examples VALUES ('RD-001015-E01', 'RD-001015', 1, 'Hui’ré inaro ba’huí. Está ancho el río. Hui’ré ichiméani. Voy a sembrar ancho (mucho).');
INSERT INTO lexical_entries VALUES ('RD-001016', 'Hui’rí', 'Hui’rí', 'hui''ri', NULL, 'Vi', 'Vi', '1. Estar largo (medida) 2. Extenso (tiempo)', 'Hue hui’rí echi cusí. Está largo el palo. Hui’rí huiriri echi ucuí. Estaba lloviendo por mucho tiempo. Hui’rira. Vt Alargar. Hui’ribé. Muy extenso.', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001016-S01', 'RD-001016', 1, 'Estar largo (medida)');
INSERT INTO senses VALUES ('RD-001016-S02', 'RD-001016', 2, 'Extenso (tiempo)');
INSERT INTO examples VALUES ('RD-001016-E01', 'RD-001016', 1, 'Hue hui’rí echi cusí. Está largo el palo. Hui’rí huiriri echi ucuí. Estaba lloviendo por mucho tiempo. Hui’rira. Vt Alargar. Hui’ribé. Muy extenso.');
INSERT INTO lexical_entries VALUES ('RD-001017', 'Huirí', 'Huirí', 'huiri', NULL, 'Vi', 'Vi', 'Estar parado', '¿Cumi huirí echi pichira? ¿Dónde está parada la escoba? [fut.: huiriméa; pl.: jahui].', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001017-S01', 'RD-001017', 1, 'Estar parado');
INSERT INTO examples VALUES ('RD-001017-E01', 'RD-001017', 1, '¿Cumi huirí echi pichira? ¿Dónde está parada la escoba? [fut.: huiriméa; pl.: jahui].');
INSERT INTO variants VALUES ('RD-001017-V01', 'RD-001017', 1, 'fut.: huiriméa; pl.: jahui');
INSERT INTO lexical_entries VALUES ('RD-001018', 'Huiríami', 'Huiríami', 'huiriami', NULL, 'Adj', 'Adj', 'Parado, nacido', 'Echi bachá huiríami ranara ju. Es el hijo primogénito.', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001018-S01', 'RD-001018', 1, 'Parado, nacido');
INSERT INTO examples VALUES ('RD-001018-E01', 'RD-001018', 1, 'Echi bachá huiríami ranara ju. Es el hijo primogénito.');
INSERT INTO lexical_entries VALUES ('RD-001019', 'Huiriba', 'Huiriba', 'huiriba', NULL, 'Vi sing', 'Vi', 'Pararse (el hecho de pararse)', 'Echo’ná yéachi huiríbari. Se paró en la puerta. [pret.: huiríbari; fut.: huiribama; pl.: jaba]. Huiribá imper Párate', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001019-S01', 'RD-001019', 1, 'Pararse (el hecho de pararse)');
INSERT INTO examples VALUES ('RD-001019-E01', 'RD-001019', 1, 'Echo’ná yéachi huiríbari. Se paró en la puerta. [pret.: huiríbari; fut.: huiribama; pl.: jaba]. Huiribá imper Párate');
INSERT INTO variants VALUES ('RD-001019-V01', 'RD-001019', 1, 'pret.: huiríbari; fut.: huiribama; pl.: jaba');
INSERT INTO lexical_entries VALUES ('RD-001020', 'Huiríbari', 'Huiríbari', 'huiribari', NULL, 'Vi', 'Vi', 'Empezar a llover', 'Echi ucuí ma huiríbari. Empezó a llover.', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
