INSERT INTO lexical_entries VALUES ('RD-001021', 'Huiribeco', 'Huiribeco', 'huiribeco', NULL, 'Adv', 'Adv', 'Después', 'Hui’ribéque nahua. Retrasa su llegada.', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
