INSERT INTO lexical_entries VALUES ('RD-001022', 'Hui’rique', 'Hui’rique', 'hui''rique', NULL, 'Adv', 'Adv', 'Mucho después', 'Hui´rique rocogó cu nahuari. Muy noche llegó. Ma hui’rique chónachi níiri. Ya era muy de noche. Hui’rique chónachi. Muy noche.', 'SRC-02', '48', '48', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
INSERT INTO senses VALUES ('RD-001022-S01', 'RD-001022', 1, 'Mucho después');
INSERT INTO examples VALUES ('RD-001022-E01', 'RD-001022', 1, 'Hui´rique rocogó cu nahuari. Muy noche llegó. Ma hui’rique chónachi níiri. Ya era muy de noche. Hui’rique chónachi. Muy noche.');
