INSERT INTO lexical_entries VALUES ('RD-001081', 'I’huí', 'I’huí', 'i''hui', NULL, 'Vt', 'Vt', '1. Enredar 2. Lo amarra por las patas', 'Cagué ma i’huiri huíi. El caballo ya enredó la soga. Cahué i’huítaga chucú. El caballo está parado enredado. ¿Churigá mi i’meri? I’huítarini ¿Cómo caíste? Me enredé.', 'SRC-02', '50', '50', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
