INSERT INTO lexical_entries VALUES ('RD-001084', 'Ihuigá', 'Ihuigá', 'ihuiga', NULL, 'S', 'S', 'Respiración', 'Diosi tamí ihuítari. Dios me dio la vida (la respiración). Binoy ihuigara. El espíritu de él. Ihuita. Vi Dar espíritu, dar vida.', 'SRC-02', '50', '51', 'Transcrito', 'Autorizada para difusión', 'Pendiente de validación lingüística');
